window.BILARA["dn02"] = window.BILARA["dn02"] || {};
window.BILARA["dn02"]["vi"] = {
  "dn2:0.1": "Trường Bộ Kinh 2 ",
  "dn2:0.2": "Kinh Sa-môn Quả ",
  "dn2:1.0": "1. Câu chuyện vua và quần thần ",
  "dn2:1.1": "Tôi được nghe như vầy",
  "dn2:1.2": "một thời Đức Thế Tôn đang trú tại vườn xoài của Jīvaka Komārabhacca ở Rājagaha, cùng với đại chúng Tỳ Kheo gồm một nghìn hai trăm năm mươi vị. ",
  "dn2:1.3": "Lúc bấy giờ, vào ngày rằm tháng Kattikangày bố-tátđêm trăng tròn, vua xứ Magadha là Ajātasattu Vedehiputta đang ngồi trên lầu cao, có quần thần vây quanh hầu hạ. ",
  "dn2:1.4": "Khi ấy, vua Magadha Ajātasattu Vedehiputta thốt lên lời cảm thán: ",
  "dn2:1.5": "'Đêm trăng đẹp quá thay! Đêm trăng rực rỡ quá thay! Đêm trăng dễ nhìn quá thay! Đêm trăng khả ái quá thay! Đêm trăng tốt lành quá thay! '",
  "dn2:1.6": "Hôm nay ta nên đến yết kiến vị sa-môn hay bà-la-môn nào để tâm được an tịnh?' ",
  "dn2:2.1": "Nghe vậy, một vị đại thần thưa với vua Magadha Ajātasattu Vedehiputta rằng: ",
  "dn2:2.2": "'Tâu Đại Vương, Pūraṇa Kassapa có giáo hội, có đồ chúng, là thủ lĩnh của đồ chúng, là thầy của đồ chúng, có danh tiếng, nổi tiếng, là vị khai tổ của giáo phái, được nhiều người tôn kính, lâu năm tu hành, từng trải, đã đến tuổi già. '",
  "dn2:2.3": "Đại Vương hãy đến yết kiến Pūraṇa Kassapa. ",
  "dn2:2.4": "Biết đâu khi yết kiến Pūraṇa Kassapa, tâm Đại Vương sẽ được an tịnh.' ",
  "dn2:2.5": "Nghe vậy, vua Magadha Ajātasattu Vedehiputta im lặng. ",
  "dn2:3.1": "Một vị đại thần khác cũng thưa với vua Magadha Ajātasattu Vedehiputta rằng: ",
  "dn2:3.2": "'Tâu Đại Vương, Makkhali Gosāla có giáo hội, có đồ chúng, là thủ lĩnh của đồ chúng, là thầy của đồ chúng, có danh tiếng, nổi tiếng, là vị khai tổ của giáo phái, được nhiều người tôn kính, lâu năm tu hành, từng trải, đã đến tuổi già. '",
  "dn2:3.3": "Đại Vương hãy đến yết kiến Makkhali Gosāla. ",
  "dn2:3.4": "Biết đâu khi yết kiến Makkhali Gosāla, tâm Đại Vương sẽ được an tịnh.' ",
  "dn2:3.5": "Nghe vậy, vua Magadha Ajātasattu Vedehiputta im lặng. ",
  "dn2:4.1": "Một vị đại thần khác cũng thưa với vua Magadha Ajātasattu Vedehiputta rằng: ",
  "dn2:4.2": "'Tâu Đại Vương, Ajita Kesakambala có giáo hội, có đồ chúng, là thủ lĩnh của đồ chúng, là thầy của đồ chúng, có danh tiếng, nổi tiếng, là vị khai tổ của giáo phái, được nhiều người tôn kính, lâu năm tu hành, từng trải, đã đến tuổi già. '",
  "dn2:4.3": "Đại Vương hãy đến yết kiến Ajita Kesakambala. ",
  "dn2:4.4": "Biết đâu khi yết kiến Ajita Kesakambala, tâm Đại Vương sẽ được an tịnh.' ",
  "dn2:4.5": "Nghe vậy, vua Magadha Ajātasattu Vedehiputta im lặng. ",
  "dn2:5.1": "Một vị đại thần khác cũng thưa với vua Magadha Ajātasattu Vedehiputta rằng: ",
  "dn2:5.2": "'Tâu Đại Vương, Pakudha Kaccāyana có giáo hội, có đồ chúng, là thủ lĩnh của đồ chúng, là thầy của đồ chúng, có danh tiếng, nổi tiếng, là vị khai tổ của giáo phái, được nhiều người tôn kính, lâu năm tu hành, từng trải, đã đến tuổi già. '",
  "dn2:5.3": "Đại Vương hãy đến yết kiến Pakudha Kaccāyana. ",
  "dn2:5.4": "Biết đâu khi yết kiến Pakudha Kaccāyana, tâm Đại Vương sẽ được an tịnh.' ",
  "dn2:5.5": "Nghe vậy, vua Magadha Ajātasattu Vedehiputta im lặng. ",
  "dn2:6.1": "Một vị đại thần khác cũng thưa với vua Magadha Ajātasattu Vedehiputta rằng: ",
  "dn2:6.2": "'Tâu Đại Vương, Sañcaya Belaṭṭhaputta có giáo hội, có đồ chúng, là thủ lĩnh của đồ chúng, là thầy của đồ chúng, có danh tiếng, nổi tiếng, là vị khai tổ của giáo phái, được nhiều người tôn kính, lâu năm tu hành, từng trải, đã đến tuổi già. '",
  "dn2:6.3": "Đại Vương hãy đến yết kiến Sañcaya Belaṭṭhaputta. ",
  "dn2:6.4": "Biết đâu khi yết kiến Sañcaya Belaṭṭhaputta, tâm Đại Vương sẽ được an tịnh.' ",
  "dn2:6.5": "Nghe vậy, vua Magadha Ajātasattu Vedehiputta im lặng. ",
  "dn2:7.1": "Một vị đại thần khác cũng thưa với vua Magadha Ajātasattu Vedehiputta rằng: ",
  "dn2:7.2": "'Tâu Đại Vương, Nigaṇṭha Nāṭaputta có giáo hội, có đồ chúng, là thủ lĩnh của đồ chúng, là thầy của đồ chúng, có danh tiếng, nổi tiếng, là vị khai tổ của giáo phái, được nhiều người tôn kính, lâu năm tu hành, từng trải, đã đến tuổi già. '",
  "dn2:7.3": "Đại Vương hãy đến yết kiến Nigaṇṭha Nāṭaputta. ",
  "dn2:7.4": "Biết đâu khi yết kiến Nigaṇṭha Nāṭaputta, tâm Đại Vương sẽ được an tịnh.' ",
  "dn2:7.5": "Nghe vậy, vua Magadha Ajātasattu Vedehiputta im lặng. ",
  "dn2:8.0": "2. Câu chuyện về Jīvaka Komārabhacca ",
  "dn2:8.1": "Lúc bấy giờ, Jīvaka Komārabhacca đang ngồi im lặng không xa vua Magadha Ajātasattu Vedehiputta. ",
  "dn2:8.2": "Khi ấy, vua Magadha Ajātasattu Vedehiputta hỏi Jīvaka Komārabhacca: ",
  "dn2:8.3": "'Này Jīvaka thân mến, sao khanh im lặng vậy?' ",
  "dn2:8.4": "'Tâu Đại Vương, Đức Thế Tôn, bậc A-la-hán, Chánh Đẳng Chánh Giác, đang trú tại vườn xoài của thần, cùng với đại chúng Tỳ Kheo gồm một nghìn hai trăm năm mươi vị. '",
  "dn2:8.5": "Ngài được tiếng tốt đẹp vang xa như sau: ",
  "dn2:8.6": "'Đây là Đức Thế Tôn, bậc A-la-hán, Chánh Đẳng Chánh Giác, đầy đủ minh và hạnh, bậc Thiện Thệ, bậc Thế Gian Giải, bậc Điều Ngự Trượng Phu Vô Thượng, bậc Thiên Nhân Sư, bậc Phật, bậc Thế Tôn.' ",
  "dn2:8.7": "Đại Vương hãy đến yết kiến Đức Thế Tôn. ",
  "dn2:8.8": "Biết đâu khi yết kiến Đức Thế Tôn, tâm Đại Vương sẽ được an tịnh.' ",
  "dn2:8.9": "'Vậy thì, Jīvaka thân mến, hãy cho chuẩn bị voi.' ",
  "dn2:9.1": "'Thưa vâng, Đại Vương.' Jīvaka Komārabhacca vâng lời vua Magadha Ajātasattu Vedehiputta, truyền chuẩn bị khoảng năm trăm voi cái và một con voi đực cho vua cưỡi, rồi tâu với vua Magadha Ajātasattu Vedehiputta: ",
  "dn2:9.2": "'Tâu Đại Vương, voi đã được chuẩn bị xong, '",
  "dn2:9.3": "xin Đại Vương tùy nghi định liệu.' ",
  "dn2:10.1": "Khi ấy, vua Magadha Ajātasattu Vedehiputta cho mỗi con voi cái chở một phụ nữ, rồi cưỡi lên con voi đực, và với đuốc sáng soi đường, ngài xuất phát từ Rājagaha với uy nghi của bậc đế vương, tiến về vườn xoài của Jīvaka Komārabhacca. ",
  "dn2:10.2": "Khi còn cách vườn xoài không xa, vua Magadha Ajātasattu Vedehiputta bỗng cảm thấy sợ hãi, hoảng loạn, dựng tóc gáy. ",
  "dn2:10.3": "Khi ấy, vua Magadha Ajātasattu Vedehiputta trong lòng sợ hãi, lo lắng, tóc dựng đứng, hỏi Jīvaka Komārabhacca rằng: ",
  "dn2:10.4": "'Jīvaka thân mến, khanh có lừa dối ta không? '",
  "dn2:10.5": "Khanh có phản ta không? ",
  "dn2:10.6": "Khanh có đưa ta vào tay kẻ thù không? ",
  "dn2:10.7": "Sao một đại chúng Tỳ Kheo đông đến một nghìn hai trăm năm mươi vị mà không nghe tiếng ho, tiếng đằng hắng hay tiếng ồn ào gì cả?' ",
  "dn2:10.8": "'Đại Vương chớ lo sợ! Đại Vương chớ lo sợ! '",
  "dn2:10.9": "Thần không lừa dối Đại Vương; ",
  "dn2:10.10": "thần không phản Đại Vương; ",
  "dn2:10.11": "thần không đưa Đại Vương vào tay kẻ thù. ",
  "dn2:10.12": "Đại Vương hãy tiến lên! Đại Vương hãy tiến lên! Kìa đèn sáng trong nhà tròn đó.' ",
  "dn2:11.0": "3. Câu hỏi về quả của đời sống sa-môn ",
  "dn2:11.1": "Khi ấy, vua Magadha Ajātasattu Vedehiputta đi bằng voi cho đến chỗ voi đi được, rồi xuống voi, đi bộ đến cửa nhà tròn, hỏi Jīvaka Komārabhacca: ",
  "dn2:11.2": "'Này Jīvaka thân mến, Đức Thế Tôn ở đâu?' ",
  "dn2:11.3": "'Tâu Đại Vương, đây là Đức Thế Tôn; '",
  "dn2:11.4": "tâu Đại Vương, đây là Đức Thế Tôn đang ngồi tựa vào cột giữa, mặt hướng về phía đông, trước mặt chúng Tỳ Kheo.' ",
  "dn2:12.1": "Khi ấy, vua Magadha Ajātasattu Vedehiputta đến chỗ Đức Thế Tôn, đứng sang một bên. ",
  "dn2:12.2": "Đứng sang một bên, vua Magadha Ajātasattu Vedehiputta nhìn khắp chúng Tỳ Kheo đang ngồi yên lặng như mặt hồ trong sáng, rồi thốt lên lời cảm thán: ",
  "dn2:12.3": "'Cầu mong hoàng tử Udāyabhadda được an tịnh như sự an tịnh mà chúng Tỳ Kheo đang có hiện nay.' ",
  "dn2:12.4": "'Tâu Đại Vương, Ngài nghĩ đến người thân mà nói vậy.' ",
  "dn2:12.5": "'Thưa Tôn giả, hoàng tử Udāyabhadda là người thân yêu của trẫm. '",
  "dn2:12.6": "Cầu mong hoàng tử Udāyabhadda được an tịnh như sự an tịnh mà chúng Tỳ Kheo đang có hiện nay.' ",
  "dn2:13.1": "Khi ấy, vua Magadha Ajātasattu Vedehiputta đảnh lễ Đức Thế Tôn, chắp tay kính chào chúng Tỳ Kheo, rồi ngồi xuống một bên. ",
  "dn2:13.2": "Ngồi xuống một bên, vua Magadha Ajātasattu Vedehiputta thưa với Đức Thế Tôn: ",
  "dn2:13.3": "'Bạch Thế Tôn, con xin phép hỏi Ngài một điều; '",
  "dn2:13.4": "nếu Thế Tôn cho phép, xin hãy trả lời câu hỏi của con.' ",
  "dn2:13.5": "'Tâu Đại Vương, Ngài cứ hỏi bất cứ điều gì.' ",
  "dn2:14.1": "'Thưa Tôn giả, các nghề thủ công trong đời này'",
  "dn2:14.2": "như người cưỡi voi, người cưỡi ngựa, người đánh xe, người bắn cung, người mang cờ, người chạy bộ, người phân phát thức ăn, các vương tử dũng mãnh, các anh hùng chiến đấu, các chiến binh mặc da thú, các con của nữ tỳ, ",
  "dn2:14.3": "thợ nấu bếp, thợ cắt tóc, thợ tắm, thợ làm bánh, thợ làm hoa, thợ nhuộm, thợ dệt, thợ đan, thợ làm gốm, thợ tính toán, thợ đếm sốvà các nghề thủ công khác tương tự; những người này sống bằng nghề của mình ngay trong đời hiện tại; ",
  "dn2:14.4": "họ dùng đó để nuôi sống bản thân, làm cho cha mẹ vui mừng, vợ con vui mừng, bạn bè vui mừng, và cúng dường sa-môn, bà-la-môn để có được phước báo cõi trời, sanh về cõi lành, hưởng quả an lạc. ",
  "dn2:14.5": "Bạch Thế Tôn, có thể chỉ ra quả báo hiện tại của đời sống sa-môn tương tự như vậy không?' ",
  "dn2:15.1": "'Tâu Đại Vương, Ngài có nhớ đã từng hỏi câu này với các sa-môn, bà-la-môn khác chưa?' ",
  "dn2:15.2": "'Bạch Thế Tôn, con đã từng hỏi câu này với các sa-môn, bà-la-môn khác rồi.' ",
  "dn2:15.3": "'Vậy thì, tâu Đại Vương, nếu Ngài không ngại, hãy kể lại họ đã trả lời như thế nào?' ",
  "dn2:15.4": "'Bạch Thế Tôn, con không ngại, khi có Thế Tôn hiện diện hay những vị như Thế Tôn.' ",
  "dn2:15.5": "'Vậy thì, tâu Đại Vương, Ngài hãy kể.' ",
  "dn2:16.0": "3.1. Quan điểm của Pūraṇa Kassapa ",
  "dn2:16.1": "'Bạch Thế Tôn, một hôm con đến gặp Pūraṇa Kassapa; sau khi chào hỏi thân mật, con ngồi xuống một bên. '",
  "dn2:16.2": "Sau khi nói những lời chào hỏi lịch sự, con ngồi xuống một bên và thưa với Pūraṇa Kassapa: ",
  "dn2:16.3": "'Thưa Kassapa, các nghề thủ công trong đời này'",
  "dn2:16.4": "như người cưỡi voi, người cưỡi ngựa, người đánh xe, người bắn cung, người mang cờ, người chạy bộ, người phân phát thức ăn, các vương tử dũng mãnh, các anh hùng chiến đấu, các chiến binh mặc da thú, các con của nữ tỳ, thợ nấu bếp, thợ cắt tóc, thợ tắm, thợ làm bánh, thợ làm hoa, thợ nhuộm, thợ dệt, thợ đan, thợ làm gốm, thợ tính toán, thợ đếm sốvà các nghề thủ công khác tương tự; những người này sống bằng nghề của mình ngay trong đời hiện tại; ",
  "dn2:16.5": "họ dùng đó để nuôi sống bản thân, làm cho cha mẹ vui mừng, vợ con vui mừng, bạn bè vui mừng, và cúng dường sa-môn, bà-la-môn để có được phước báo cõi trời, sanh về cõi lành, hưởng quả an lạc. ",
  "dn2:16.6": "Có thể chỉ ra quả báo hiện tại của đời sống sa-môn tương tự như vậy không?' ",
  "dn2:17.1": "Bạch Thế Tôn, khi con hỏi vậy, Pūraṇa Kassapa trả lời con: ",
  "dn2:17.2": "'Tâu Đại Vương, người làm, người sai làm, người chặt, người sai chặt, người nấu, người sai nấu, người gây khổ, người sai gây khổ, người làm buồn, người sai làm buồn, người giết sinh vật, người lấy của không cho, người khoét vách tường, người cướp của, người vào nhà đơn độc, người chặn đường, người tà dâm, người nói dốingười làm những điều đó đều không tạo nghiệp ác. Dù ai dùng bánh xe có lưỡi dao bén mà giết hại tất cả sinh vật trên cõi đất này thành một đống thịt, cũng không có tội lỗi nào từ đó, không có nghiệp ác nào đến. '",
  "dn2:17.3": "Dù ai đi dọc bờ nam sông Hằng mà giết, mà chém, mà cắt, mà sai cắt, mà nướng, mà sai nướng, cũng không có tội lỗi nào từ đó, không có nghiệp ác nào đến. ",
  "dn2:17.4": "Dù ai đi dọc bờ bắc sông Hằng mà bố thí, mà sai bố thí, mà cúng tế, mà sai cúng tế, cũng không có phước báo nào từ đó, không có phước đức nào đến. ",
  "dn2:17.5": "Bố thí, tự chế, kiêng giữ, nói thậtkhông có phước báo nào, không có phước đức nào đến.' ",
  "dn2:18.1": "Bạch Thế Tôn, khi con hỏi Pūraṇa Kassapa về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời về thuyết vô nghiệp. ",
  "dn2:18.2": "Bạch Thế Tôn, giống như người hỏi xoài lại nói nhàu; hỏi nhàu lại nói xoài; ",
  "dn2:18.3": "cũng vậy, khi con hỏi Pūraṇa Kassapa về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời về thuyết vô nghiệp. ",
  "dn2:18.4": "Con nghĩ: ",
  "dn2:18.5": "'Sao một người như ta lại có thể khinh thường một sa-môn hay bà-la-môn đang sống trong lãnh thổ của ta?' ",
  "dn2:18.6": "Con không tán thán cũng không phản đối lời nói của Pūraṇa Kassapa. ",
  "dn2:18.7": "Không tán thán, không phản đối, lòng không vui, không nói lời bất mãn, không chấp nhận lời đó mà cũng không bác bỏ, con đứng dậy rồi ra đi. ",
  "dn2:19.0": "3.2. Quan điểm của Makkhali Gosāla ",
  "dn2:19.1": "Bạch Thế Tôn, một hôm con đến gặp Makkhali Gosāla; sau khi chào hỏi thân mật, con ngồi xuống một bên. ",
  "dn2:19.2": "Sau khi nói những lời chào hỏi lịch sự, con ngồi xuống một bên và thưa với Makkhali Gosāla: ",
  "dn2:19.3": "'Thưa Gosāla, các nghề thủ công trong đời này... '",
  "dn2:19.4": "Có thể chỉ ra quả báo hiện tại của đời sống sa-môn tương tự như vậy không?' ",
  "dn2:20.1": "Bạch Thế Tôn, khi con hỏi vậy, Makkhali Gosāla trả lời con: ",
  "dn2:20.2": "'Tâu Đại Vương, không có nguyên nhân, không có điều kiện nào dẫn đến sự ô nhiễm của chúng sinh; chúng sinh bị ô nhiễm không do nguyên nhân, không do điều kiện. '",
  "dn2:20.3": "Không có nguyên nhân, không có điều kiện nào dẫn đến sự thanh tịnh của chúng sinh; ",
  "dn2:20.4": "chúng sinh được thanh tịnh không do nguyên nhân, không do điều kiện. ",
  "dn2:20.5": "Không có tự lực, không có tha lực, không có nỗ lực của con người, không có sức mạnh, không có tinh tấn, không có sức chịu đựng, không có cố gắng của con người. ",
  "dn2:20.6": "Tất cả chúng sinh, tất cả sinh linh, tất cả loài hữu tình, tất cả sinh vậtkhông có quyền tự quyết, không có sức mạnh, không có tinh tấnbị định mệnh, hoàn cảnh và bản chất của họ chi phối, hưởng khổ vui trong sáu loại tái sinh. ",
  "dn2:20.7": "Có một trăm bốn mươi vạn chủng loại nguồn gốc tái sinh, sáu trăm loại, sáu loại, năm trăm nghiệp, năm nghiệp, ba nghiệp, nửa nghiệp; sáu mươi hai con đường tu hành, sáu mươi hai kiếp trung gian, sáu loại sinh thành, tám giai đoạn người, bốn nghìn chín trăm tà mạng, bốn nghìn chín trăm du sĩ, bốn nghìn chín trăm chỗ ở của rồng, hai nghìn căn, ba trăm địa ngục, ba mươi sáu cõi bụi trần, bảy thai nhi có tưởng, bảy thai nhi không tưởng, bảy thai nhi Nigantha, bảy cõi trời, bảy cõi người, bảy quỷ, bảy hồ, bảy hang, bảy trăm hang, bảy vực thẳm, bảy trăm vực thẳm, bảy giấc mơ, bảy trăm giấc mơ; tám mươi bốn ngàn đại kiếptrải qua đó, người ngu và người trí đều sẽ đi lang thang, luân hồi, và đi đến chỗ tận cùng của khổ đau. ",
  "dn2:20.8": "Ở đó không có điều này: 'Nhờ giới này, hạnh này, khổ hạnh này, phạm hạnh này, ta sẽ làm chín muồi nghiệp chưa chín muồi, hoặc chạm xúc và diệt tận nghiệp đã chín muồi.' ",
  "dn2:20.9": "Khổ vui được đo lường, luân hồi có giới hạn; không có tăng hay giảm, không có cao hay thấp. ",
  "dn2:20.10": "Cũng như một cuộn chỉ khi ném ra sẽ tự cuộn ra hết; ",
  "dn2:20.11": "cũng vậy, người ngu và người trí đều đã đi lang thang, luân hồi, và sẽ đi đến chỗ tận cùng của khổ đau.' ",
  "dn2:21.1": "Bạch Thế Tôn, khi con hỏi Makkhali Gosāla về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời về thuyết thanh tịnh qua luân hồi. ",
  "dn2:21.2": "Bạch Thế Tôn, giống như người hỏi xoài lại nói nhàu; hỏi nhàu lại nói xoài; ",
  "dn2:21.3": "cũng vậy, khi con hỏi Makkhali Gosāla về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời về thuyết thanh tịnh qua luân hồi. ",
  "dn2:21.4": "Con nghĩ: ",
  "dn2:21.5": "'Sao một người như ta lại có thể khinh thường một sa-môn hay bà-la-môn đang sống trong lãnh thổ của ta?' ",
  "dn2:21.6": "Con không tán thán cũng không phản đối lời nói của Makkhali Gosāla. ",
  "dn2:21.7": "Không tán thán, không phản đối, lòng không vui, không nói lời bất mãn, không chấp nhận lời đó mà cũng không bác bỏ, con đứng dậy rồi ra đi. ",
  "dn2:22.0": "3.3. Quan điểm của Ajita Kesakambala ",
  "dn2:22.1": "Bạch Thế Tôn, một hôm con đến gặp Ajita Kesakambala; sau khi chào hỏi thân mật, con ngồi xuống một bên. ",
  "dn2:22.2": "Sau khi nói những lời chào hỏi lịch sự, con ngồi xuống một bên và thưa với Ajita Kesakambala: ",
  "dn2:22.3": "'Thưa Ajita, các nghề thủ công trong đời này... '",
  "dn2:22.4": "Có thể chỉ ra quả báo hiện tại của đời sống sa-môn tương tự như vậy không?' ",
  "dn2:23.1": "Bạch Thế Tôn, khi con hỏi vậy, Ajita Kesakambala trả lời con: ",
  "dn2:23.2": "'Tâu Đại Vương, không có bố thí, không có cúng tế, không có hiến tế; không có quả báo của nghiệp thiện ác; không có đời này, không có đời sau; không có mẹ, không có cha; không có các loài sinh hóa; trong đời này không có sa-môn hay bà-la-môn chân chánh, thực hành đúng đắn, những người bằng thắng trí của mình tự thân chứng ngộ và tuyên thuyết cả đời này lẫn đời sau. '",
  "dn2:23.3": "Con người gồm bốn đại. Khi chết, đất trở về đất, nước trở về nước, lửa trở về lửa, gió trở về gió; các căn tan vào hư không. ",
  "dn2:23.4": "Bốn người đàn ông cùng chiếc giường là người thứ năm khiêng xác đi. ",
  "dn2:23.5": "Người ta thấy dấu chân đến lò thiêu. ",
  "dn2:23.6": "Xương trở thành màu bồ câu, tro bụi tan biến. ",
  "dn2:23.7": "Bố thí là lời nói của kẻ ngu. ",
  "dn2:23.8": "Những ai nói có thực thể đều là lời trống rỗng, dối trá. ",
  "dn2:23.9": "Người ngu cũng như người trí, khi thân tan rã đều bị hủy diệt, tiêu vong, không còn tồn tại sau khi chết.' ",
  "dn2:24.1": "Bạch Thế Tôn, khi con hỏi Ajita Kesakambala về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời về thuyết đoạn diệt. ",
  "dn2:24.2": "Bạch Thế Tôn, giống như người hỏi xoài lại nói nhàu; hỏi nhàu lại nói xoài; ",
  "dn2:24.3": "cũng vậy, khi con hỏi Ajita Kesakambala về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời về thuyết đoạn diệt. ",
  "dn2:24.4": "Con nghĩ: ",
  "dn2:24.5": "'Sao một người như ta lại có thể khinh thường một sa-môn hay bà-la-môn đang sống trong lãnh thổ của ta?' ",
  "dn2:24.6": "Con không tán thán cũng không phản đối lời nói của Ajita Kesakambala. ",
  "dn2:24.7": "Không tán thán, không phản đối, lòng không vui, không nói lời bất mãn, không chấp nhận lời đó mà cũng không bác bỏ, con đứng dậy rồi ra đi. ",
  "dn2:25.0": "3.4. Quan điểm của Pakudha Kaccāyana ",
  "dn2:25.1": "Bạch Thế Tôn, một hôm con đến gặp Pakudha Kaccāyana; sau khi chào hỏi thân mật, con ngồi xuống một bên. ",
  "dn2:25.2": "Sau khi nói những lời chào hỏi lịch sự, con ngồi xuống một bên và thưa với Pakudha Kaccāyana: ",
  "dn2:25.3": "'Thưa Kaccāyana, các nghề thủ công trong đời này... '",
  "dn2:25.4": "Có thể chỉ ra quả báo hiện tại của đời sống sa-môn tương tự như vậy không?' ",
  "dn2:26.1": "Bạch Thế Tôn, khi con hỏi vậy, Pakudha Kaccāyana trả lời con: ",
  "dn2:26.2": "'Tâu Đại Vương, có bảy thực thể này không được tạo ra, không do ai làm ra, không được sinh ra, không có người tạo tác, bất động, vững như núi, trụ như cây cột. '",
  "dn2:26.3": "Chúng không lay chuyển, không biến đổi, không cản trở lẫn nhau, không thể đem lại khổ hay vui hay cả hai cho nhau. ",
  "dn2:26.4": "Bảy thực thể đó là gì? ",
  "dn2:26.5": "Đất, nước, lửa, gió, khổ, vui, và linh hồn là thứ bảy",
  "dn2:26.6": "bảy thực thể này không được tạo ra, không do ai làm ra, không được sinh ra, không có người tạo tác, bất động, vững như núi, trụ như cây cột. ",
  "dn2:26.7": "Chúng không lay chuyển, không biến đổi, không cản trở lẫn nhau, không thể đem lại khổ hay vui hay cả hai cho nhau. ",
  "dn2:26.8": "Trong đó không có ai giết, ai sai giết, ai nghe, ai sai nghe, ai biết, ai sai biết. ",
  "dn2:26.9": "Dù ai dùng kiếm bén chặt đầu người khác, cũng không có ai tước đoạt mạng sống của ai; ",
  "dn2:26.10": "kiếm chỉ lọt vào khoảng hở giữa bảy thực thể đó mà thôi.' ",
  "dn2:27.1": "Bạch Thế Tôn, khi con hỏi Pakudha Kaccāyana về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời lạc đề sang chuyện khác. ",
  "dn2:27.2": "Bạch Thế Tôn, giống như người hỏi xoài lại nói nhàu; hỏi nhàu lại nói xoài; ",
  "dn2:27.3": "cũng vậy, khi con hỏi Pakudha Kaccāyana về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời lạc đề sang chuyện khác. ",
  "dn2:27.4": "Con nghĩ: ",
  "dn2:27.5": "'Sao một người như ta lại có thể khinh thường một sa-môn hay bà-la-môn đang sống trong lãnh thổ của ta?' ",
  "dn2:27.6": "Con không tán thán cũng không phản đối lời nói của Pakudha Kaccāyana. ",
  "dn2:27.7": "Không tán thán, không phản đối, lòng không vui, không nói lời bất mãn, không chấp nhận lời đó mà cũng không bác bỏ, con đứng dậy rồi ra đi. ",
  "dn2:28.0": "3.5. Quan điểm của Nigaṇṭha Nāṭaputta ",
  "dn2:28.1": "Bạch Thế Tôn, một hôm con đến gặp Nigaṇṭha Nāṭaputta; sau khi chào hỏi thân mật, con ngồi xuống một bên. ",
  "dn2:28.2": "Sau khi nói những lời chào hỏi lịch sự, con ngồi xuống một bên và thưa với Nigaṇṭha Nāṭaputta: ",
  "dn2:28.3": "'Thưa Aggivessana, các nghề thủ công trong đời này... '",
  "dn2:28.4": "Có thể chỉ ra quả báo hiện tại của đời sống sa-môn tương tự như vậy không?' ",
  "dn2:29.1": "Bạch Thế Tôn, khi con hỏi vậy, Nigaṇṭha Nāṭaputta trả lời con: ",
  "dn2:29.2": "'Tâu Đại Vương, vị Nigantha ở đây được thu thúc bởi bốn loại kiêng giữ. '",
  "dn2:29.3": "Thưa Đại Vương, thế nào là vị Nigantha được thu thúc bởi bốn loại kiêng giữ? ",
  "dn2:29.4": "Tâu Đại Vương, vị Nigantha ở đây ngăn chặn tất cả nước, có tất cả nước chặn lại, gột sạch tất cả nước, và thấm nhuần tất cả nước. ",
  "dn2:29.5": "Như vậy, tâu Đại Vương, vị Nigantha được thu thúc bởi bốn loại kiêng giữ. ",
  "dn2:29.6": "Vì vị Nigantha được thu thúc bởi bốn loại kiêng giữ như vậy, ",
  "dn2:29.7": "nên vị ấy được gọi là người đã đạt đến tự ngã, đã chế ngự tự ngã, đã an trú tự ngã.' ",
  "dn2:30.1": "Bạch Thế Tôn, khi con hỏi Nigaṇṭha Nāṭaputta về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời về bốn loại thu thúc. ",
  "dn2:30.2": "Bạch Thế Tôn, giống như người hỏi xoài lại nói nhàu; hỏi nhàu lại nói xoài; ",
  "dn2:30.3": "cũng vậy, khi con hỏi Nigaṇṭha Nāṭaputta về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời về bốn loại thu thúc. ",
  "dn2:30.4": "Con nghĩ: ",
  "dn2:30.5": "'Sao một người như ta lại có thể khinh thường một sa-môn hay bà-la-môn đang sống trong lãnh thổ của ta?' ",
  "dn2:30.6": "Con không tán thán cũng không phản đối lời nói của Nigaṇṭha Nāṭaputta. ",
  "dn2:30.7": "Không tán thán, không phản đối, lòng không vui, không nói lời bất mãn, không chấp nhận lời đó mà cũng không bác bỏ, con đứng dậy rồi ra đi. ",
  "dn2:31.0": "3.6. Quan điểm của Sañcaya Belaṭṭhaputta ",
  "dn2:31.1": "Bạch Thế Tôn, một hôm con đến gặp Sañcaya Belaṭṭhaputta; sau khi chào hỏi thân mật, con ngồi xuống một bên. ",
  "dn2:31.2": "Sau khi nói những lời chào hỏi lịch sự, con ngồi xuống một bên và thưa với Sañcaya Belaṭṭhaputta: ",
  "dn2:31.3": "'Thưa Sañcaya, các nghề thủ công trong đời này... '",
  "dn2:31.4": "Có thể chỉ ra quả báo hiện tại của đời sống sa-môn tương tự như vậy không?' ",
  "dn2:32.1": "Bạch Thế Tôn, khi con hỏi vậy, Sañcaya Belaṭṭhaputta trả lời con: ",
  "dn2:32.2": "'Nếu ông hỏi tôi rằng có đời sau khôngnếu tôi nghĩ có đời sau, tôi sẽ trả lời có đời sau. '",
  "dn2:32.3": "Nhưng tôi không nghĩ vậy, tôi không nghĩ ngược lại, tôi không nghĩ khác đi, tôi không phủ nhận, tôi cũng không không phủ nhận. ",
  "dn2:32.4": "Không có đời sau... ",
  "dn2:32.5": "Vừa có vừa không có đời sau... ",
  "dn2:32.6": "Không phải có cũng không phải không có đời sau... ",
  "dn2:32.7": "Có các loài sinh hóa... ",
  "dn2:32.8": "Không có các loài sinh hóa... ",
  "dn2:32.9": "Vừa có vừa không có các loài sinh hóa... ",
  "dn2:32.10": "Không phải có cũng không phải không có các loài sinh hóa... ",
  "dn2:32.11": "Có quả báo của nghiệp thiện ác... ",
  "dn2:32.12": "Không có quả báo của nghiệp thiện ác... ",
  "dn2:32.13": "Vừa có vừa không có quả báo của nghiệp thiện ác... ",
  "dn2:32.14": "Không phải có cũng không phải không có quả báo của nghiệp thiện ác... ",
  "dn2:32.15": "Như Lai tồn tại sau khi chết... ",
  "dn2:32.16": "Như Lai không tồn tại sau khi chết... ",
  "dn2:32.17": "Như Lai vừa tồn tại vừa không tồn tại sau khi chết... ",
  "dn2:32.18": "Nếu ông hỏi tôi rằng Như Lai không phải tồn tại cũng không phải không tồn tại sau khi chếtnếu tôi nghĩ vậy, tôi sẽ trả lời vậy. Nhưng tôi không nghĩ vậy, tôi không nghĩ ngược lại, tôi không nghĩ khác đi, tôi không phủ nhận, tôi cũng không không phủ nhận. ",
  "dn2:32.19": "Tôi không nghĩ vậy, tôi không nghĩ ngược lại, tôi không nghĩ khác đi, tôi không phủ nhận, tôi cũng không không phủ nhận.' ",
  "dn2:33.1": "Bạch Thế Tôn, khi con hỏi Sañcaya Belaṭṭhaputta về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời bằng cách lảng tránh. ",
  "dn2:33.2": "Bạch Thế Tôn, giống như người hỏi xoài lại nói nhàu; hỏi nhàu lại nói xoài; ",
  "dn2:33.3": "cũng vậy, khi con hỏi Sañcaya Belaṭṭhaputta về quả báo hiện tại của đời sống sa-môn, ông ấy trả lời bằng cách lảng tránh. ",
  "dn2:33.4": "Con nghĩ: ",
  "dn2:33.5": "'Đây là kẻ ngu nhất, mê muội nhất trong số các sa-môn, bà-la-môn đó. '",
  "dn2:33.6": "Sao khi được hỏi về quả báo hiện tại của đời sống sa-môn lại trả lời bằng cách lảng tránh?' ",
  "dn2:33.7": "Con lại nghĩ: ",
  "dn2:33.8": "'Sao một người như ta lại có thể khinh thường một sa-môn hay bà-la-môn đang sống trong lãnh thổ của ta?' ",
  "dn2:33.9": "Con không tán thán cũng không phản đối lời nói của Sañcaya Belaṭṭhaputta. ",
  "dn2:33.10": "Không tán thán, không phản đối, lòng không vui, không nói lời bất mãn, không chấp nhận lời đó mà cũng không bác bỏ, con đứng dậy rồi ra đi. ",
  "dn2:34.0.1": "4. Quả của đời sống sa-môn ",
  "dn2:34.0.2": "4.1. Quả sa-môn thứ nhất có thể thấy ngay trong đời này ",
  "dn2:34.1": "Bạch Thế Tôn, nay con xin phép hỏi Thế Tôn rằng: ",
  "dn2:34.2": "'Thưa Tôn giả, các nghề thủ công trong đời này '",
  "dn2:34.3": "như người cưỡi voi, người cưỡi ngựa, người đánh xe, người bắn cung, người mang cờ, người chạy bộ, người phân phát thức ăn, các vương tử dũng mãnh, các anh hùng chiến đấu, các chiến binh mặc da thú, các con của nữ tỳ, ",
  "dn2:34.4": "thợ nấu bếp, thợ cắt tóc, thợ tắm, thợ làm bánh, thợ làm hoa, thợ nhuộm, thợ dệt, thợ đan, thợ làm gốm, thợ tính toán, thợ đếm sốvà các nghề thủ công khác tương tự; những người này sống bằng nghề của mình ngay trong đời hiện tại; ",
  "dn2:34.5": "họ dùng đó để nuôi sống bản thân, làm cho cha mẹ vui mừng, vợ con vui mừng, bạn bè vui mừng, và cúng dường sa-môn, bà-la-môn để có được phước báo cõi trời, sanh về cõi lành, hưởng quả an lạc. ",
  "dn2:34.6": "Có thể chỉ ra quả báo hiện tại của đời sống sa-môn tương tự như vậy không?' ",
  "dn2:34.7": "'Được, tâu Đại Vương. '",
  "dn2:34.8": "Vậy thì, tâu Đại Vương, ta sẽ hỏi lại Ngài về điều này. Ngài hãy trả lời theo ý của mình. ",
  "dn2:35.1": "Tâu Đại Vương, Ngài nghĩ sao",
  "dn2:35.2": "giả sử Ngài có một người đày tớ, làm thuê, dậy sớm, ngủ muộn, làm theo lệnh, có cách ứng xử dễ chịu, nói lời dịu dàng, nhìn vào mặt mà phục vụ. ",
  "dn2:35.3": "Người ấy nghĩ: ",
  "dn2:35.4": "'Thật kỳ diệu thay! Thật phi thường thay! Quả của phước đức, sự trổ quả của phước đức! '",
  "dn2:35.5": "Vua Magadha Ajātasattu Vedehiputta này là người; ta cũng là người. ",
  "dn2:35.6": "Vua Magadha Ajātasattu Vedehiputta được hưởng thụ năm món dục lạc đầy đủ, như một vị trời. ",
  "dn2:35.7": "Còn ta là đày tớ của ngài, làm thuê, dậy sớm, ngủ muộn, làm theo lệnh, có cách ứng xử dễ chịu, nói lời dịu dàng, nhìn vào mặt mà phục vụ. ",
  "dn2:35.8": "Ta nên tạo phước đức. ",
  "dn2:35.9": "Thôi ta hãy cạo râu tóc, đắp y vàng, xuất gia từ gia đình sống không nhà.' ",
  "dn2:35.10": "Sau đó, người ấy cạo râu tóc, đắp y vàng, xuất gia từ gia đình sống không nhà. ",
  "dn2:35.11": "Sau khi xuất gia như vậy, người ấy sống thu thúc thân, thu thúc lời nói, thu thúc tâm ý, bằng lòng với thức ăn và y phục tối thiểu, vui vẻ với sự ẩn cư. ",
  "dn2:35.12": "Nếu có người tâu với Đại Vương rằng: ",
  "dn2:35.13": "'Tâu Đại Vương, Ngài có biết khôngngười đày tớ kia trước đây làm thuê cho Ngài, dậy sớm, ngủ muộn, làm theo lệnh, có cách ứng xử dễ chịu, nói lời dịu dàng, nhìn vào mặt mà phục vụ; '",
  "dn2:35.14": "người ấy, tâu Đại Vương, đã cạo râu tóc, đắp y vàng, xuất gia từ gia đình sống không nhà. ",
  "dn2:35.15": "Sau khi xuất gia như vậy, người ấy sống thu thúc thân, thu thúc lời nói, thu thúc tâm ý, bằng lòng với thức ăn và y phục tối thiểu, vui vẻ với sự ẩn cư.' ",
  "dn2:35.16": "Liệu Đại Vương có nói rằng: ",
  "dn2:35.17": "'Hãy đưa người đó đến cho ta, để người ấy lại làm đày tớ, làm thuê, dậy sớm, ngủ muộn, làm theo lệnh, có cách ứng xử dễ chịu, nói lời dịu dàng, nhìn vào mặt mà phục vụ?' ",
  "dn2:36.1": "'Thưa không, bạch Thế Tôn. '",
  "dn2:36.2": "Trái lại, chúng con sẽ đảnh lễ người ấy, đứng dậy chào người ấy, mời người ấy ngồi, cung thỉnh người ấy và cúng dường người ấy y phục, thức ăn, chỗ ở, thuốc men và các vật dụng, và sẽ lo việc hộ trì bảo vệ người ấy đúng theo pháp.' ",
  "dn2:36.3": "'Tâu Đại Vương, Ngài nghĩ sao'",
  "dn2:36.4": "nếu như vậy, có quả báo hiện tại của đời sống sa-môn hay không?' ",
  "dn2:36.5": "'Bạch Thế Tôn, chắc chắn nếu như vậy thì có quả báo hiện tại của đời sống sa-môn.' ",
  "dn2:36.6": "'Tâu Đại Vương, đây là quả báo hiện tại đầu tiên của đời sống sa-môn mà ta chỉ ra cho Ngài.' ",
  "dn2:37.0": "4.2. Quả sa-môn thứ hai có thể thấy ngay trong đời này ",
  "dn2:37.1": "'Bạch Thế Tôn, có thể chỉ ra một quả báo hiện tại khác của đời sống sa-môn tương tự như vậy không?' ",
  "dn2:37.2": "'Được, tâu Đại Vương. '",
  "dn2:37.3": "Vậy thì, tâu Đại Vương, ta sẽ hỏi lại Ngài về điều này. Ngài hãy trả lời theo ý của mình. ",
  "dn2:37.4": "Tâu Đại Vương, Ngài nghĩ sao",
  "dn2:37.5": "giả sử Ngài có một người nông dân, chủ gia đình, làm ruộng, tích lũy tài sản. ",
  "dn2:37.6": "Người ấy nghĩ: ",
  "dn2:37.7": "'Thật kỳ diệu thay! Thật phi thường thay! Quả của phước đức, sự trổ quả của phước đức! '",
  "dn2:37.8": "Vua Magadha Ajātasattu Vedehiputta này là người; ta cũng là người. ",
  "dn2:37.9": "Vua Magadha Ajātasattu Vedehiputta được hưởng thụ năm món dục lạc đầy đủ, như một vị trời. ",
  "dn2:37.10": "Còn ta là nông dân, chủ gia đình, làm ruộng, tích lũy tài sản. ",
  "dn2:37.11": "Ta nên tạo phước đức. ",
  "dn2:37.12": "Thôi ta hãy cạo râu tóc, đắp y vàng, xuất gia từ gia đình sống không nhà.' ",
  "dn2:37.13": "Sau đó, người ấy từ bỏ ít hay nhiều tài sản, từ bỏ ít hay nhiều quyến thuộc, cạo râu tóc, đắp y vàng, xuất gia từ gia đình sống không nhà. ",
  "dn2:37.14": "Sau khi xuất gia như vậy, người ấy sống thu thúc thân, thu thúc lời nói, thu thúc tâm ý, bằng lòng với thức ăn và y phục tối thiểu, vui vẻ với sự ẩn cư. ",
  "dn2:37.15": "Nếu có người tâu với Đại Vương rằng: ",
  "dn2:37.16": "'Tâu Đại Vương, Ngài có biết khôngngười nông dân kia, chủ gia đình, làm ruộng, tích lũy tài sản; '",
  "dn2:37.17": "người ấy, tâu Đại Vương, đã cạo râu tóc, đắp y vàng, xuất gia từ gia đình sống không nhà. ",
  "dn2:37.18": "Sau khi xuất gia như vậy, người ấy sống thu thúc thân, thu thúc lời nói, thu thúc tâm ý, bằng lòng với thức ăn và y phục tối thiểu, vui vẻ với sự ẩn cư.' ",
  "dn2:37.19": "Liệu Đại Vương có nói rằng: ",
  "dn2:37.20": "'Hãy đưa người đó đến cho ta, để người ấy lại làm nông dân, chủ gia đình, làm ruộng, tích lũy tài sản?' ",
  "dn2:38.1": "'Thưa không, bạch Thế Tôn. '",
  "dn2:38.2": "Trái lại, chúng con sẽ đảnh lễ người ấy, đứng dậy chào người ấy, mời người ấy ngồi, cung thỉnh người ấy và cúng dường người ấy y phục, thức ăn, chỗ ở, thuốc men và các vật dụng, và sẽ lo việc hộ trì bảo vệ người ấy đúng theo pháp.' ",
  "dn2:38.3": "'Tâu Đại Vương, Ngài nghĩ sao'",
  "dn2:38.4": "nếu như vậy, có quả báo hiện tại của đời sống sa-môn hay không?' ",
  "dn2:38.5": "'Bạch Thế Tôn, chắc chắn nếu như vậy thì có quả báo hiện tại của đời sống sa-môn.' ",
  "dn2:38.6": "'Tâu Đại Vương, đây là quả báo hiện tại thứ hai của đời sống sa-môn mà ta chỉ ra cho Ngài.' ",
  "dn2:39.0": "4.3. Quả sa-môn cao thượng hơn ",
  "dn2:39.1": "'Bạch Thế Tôn, có thể chỉ ra một quả báo hiện tại khác của đời sống sa-môn cao thượng hơn và vi diệu hơn hai quả báo đó không?' ",
  "dn2:39.2": "'Được, tâu Đại Vương. '",
  "dn2:39.3": "Vậy thì, tâu Đại Vương, hãy lắng nghe và chú tâm kỹ, ta sẽ nói.' ",
  "dn2:39.4": "'Thưa vâng, bạch Thế Tôn.' Vua Magadha Ajātasattu Vedehiputta vâng lời Đức Thế Tôn. ",
  "dn2:39.5": "Đức Thế Tôn dạy: ",
  "dn2:40.1": "'Tâu Đại Vương, ở đây, một Như Lai xuất hiện trên đời, là bậc A-la-hán, Chánh Đẳng Chánh Giác, đầy đủ minh và hạnh, bậc Thiện Thệ, bậc Thế Gian Giải, bậc Điều Ngự Trượng Phu Vô Thượng, bậc Thiên Nhân Sư, bậc Phật, bậc Thế Tôn. '",
  "dn2:40.2": "Ngài tự thân chứng ngộ và tuyên thuyết thế giới này gồm cả cõi trời, ma vương, phạm thiên, cùng sa-môn, bà-la-môn, thiên và nhân. ",
  "dn2:40.3": "Ngài giảng Pháp tốt đẹp ở đầu, tốt đẹp ở giữa, tốt đẹp ở cuối, có ý nghĩa, có văn cú, trình bày phạm hạnh hoàn toàn đầy đủ và trong sáng. ",
  "dn2:41.1": "Một gia chủ hay con gia chủ, hay người sanh trong gia tộc nào đó, nghe Pháp ấy. ",
  "dn2:41.2": "Sau khi nghe Pháp ấy, người ấy khởi lên lòng tin đối với Như Lai. ",
  "dn2:41.3": "Với lòng tin đó, người ấy suy nghĩ: ",
  "dn2:41.4": "'Cuộc sống tại gia chật hẹp, đầy bụi trần; đời sống xuất gia thênh thang. '",
  "dn2:41.5": "Không dễ gì khi sống tại gia mà thực hành phạm hạnh hoàn toàn đầy đủ, hoàn toàn trong sáng, tinh khiết như vỏ ốc được đánh bóng. ",
  "dn2:41.6": "Thôi ta hãy cạo râu tóc, đắp y vàng, xuất gia từ gia đình sống không nhà.' ",
  "dn2:41.7": "Sau đó, người ấy từ bỏ ít hay nhiều tài sản, từ bỏ ít hay nhiều quyến thuộc, cạo râu tóc, đắp y vàng, xuất gia từ gia đình sống không nhà. ",
  "dn2:42.1": "Sau khi xuất gia như vậy, người ấy sống thu thúc theo giới bổn Ba-la-đề-mộc-xoa, đầy đủ oai nghi và chánh hạnh, thấy sợ hãi trong các lỗi nhỏ nhặt, thọ trì và học tập các học pháp, có thân nghiệp và khẩu nghiệp thiện, mạng sống thanh tịnh, đầy đủ giới hạnh, phòng hộ các căn, có niệm và tỉnh giác, biết đủ. ",
  "dn2:43.0.1": "4.3.1. Giới ",
  "dn2:43.0.2": "4.3.1.1. Tiểu giới ",
  "dn2:43.1": "Thưa Đại Vương, thế nào là Tỳ Kheo đầy đủ giới hạnh? ",
  "dn2:43.2": "Tâu Đại Vương, ở đây Tỳ Kheo từ bỏ sát sanh, sống tránh xa sát sanh, bỏ gậy, bỏ kiếm, có lòng hổ thẹn, có lòng từ bi, thương xót tất cả loài hữu tình. ",
  "dn2:43.3": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:43.4": "Từ bỏ trộm cắp, sống tránh xa trộm cắp, chỉ lấy những gì được cho, chờ đợi những gì được cho, không trộm cắp, sống tự ngã trong sạch. ",
  "dn2:43.5": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:43.6": "Từ bỏ phi phạm hạnh, sống phạm hạnh, sống xa cách, từ bỏ việc giao hợp là pháp của người thế tục. ",
  "dn2:43.7": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:44.1": "Từ bỏ nói dối, sống tránh xa nói dối, nói lời chân thật, trung thực, đáng tin cậy, đáng nương tựa, không phản bội đời. ",
  "dn2:44.2": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:44.3": "Từ bỏ nói đâm thọc, sống tránh xa nói đâm thọc; những gì nghe ở đây không nói lại ở kia để gây chia rẽ; những gì nghe ở kia không nói lại ở đây để gây chia rẽ. Như vậy vị ấy hòa giải những người bất hòa, thêm thắt cho những người đã hòa thuận, vui với sự hòa hợp, vui thích trong sự hòa hợp, hân hoan trong sự hòa hợp, nói những lời tạo ra sự hòa hợp. ",
  "dn2:44.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:44.5": "Từ bỏ lời nói thô ác, sống tránh xa lời nói thô ác; nói những lời êm dịu, dễ nghe, đáng yêu, thấm vào lòng, lịch sự, được nhiều người ưa thích và yêu mến. ",
  "dn2:44.6": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:44.7": "Từ bỏ nói lời vô nghĩa, sống tránh xa nói lời vô nghĩa; nói đúng thời, nói thật, nói có lợi ích, nói Pháp, nói Luật; nói những lời đáng giá, hợp thời, có lý do, có giới hạn, liên quan đến lợi ích. ",
  "dn2:44.8": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:45.1": "Tránh xa việc phá hại hạt giống và thực vật... ",
  "dn2:45.2": "Ăn một bữa, không ăn ban đêm, từ bỏ ăn ngoài giờ. ",
  "dn2:45.3": "Tránh xa xem múa, hát, nhạc và các trò giải trí. ",
  "dn2:45.4": "Tránh xa đeo vòng hoa, xoa nước hoa, trang điểm bằng hoa thơm và phấn. ",
  "dn2:45.5": "Tránh xa dùng giường cao và giường lớn. ",
  "dn2:45.6": "Tránh xa nhận vàng và bạc. ",
  "dn2:45.7": "Tránh xa nhận thóc lúa sống. ",
  "dn2:45.8": "Tránh xa nhận thịt sống. ",
  "dn2:45.9": "Tránh xa nhận phụ nữ và thiếu nữ. ",
  "dn2:45.10": "Tránh xa nhận nô tỳ nam và nữ. ",
  "dn2:45.11": "Tránh xa nhận dê và cừu. ",
  "dn2:45.12": "Tránh xa nhận gà và heo. ",
  "dn2:45.13": "Tránh xa nhận voi, trâu bò, ngựa. ",
  "dn2:45.14": "Tránh xa nhận ruộng đất. ",
  "dn2:45.15": "Tránh xa làm sứ giả hay đưa tin. ",
  "dn2:45.16": "Tránh xa mua bán. ",
  "dn2:45.17": "Tránh xa cân điêu, đo lường gian, đong đong thiếu. ",
  "dn2:45.18": "Tránh xa hối lộ, lừa dối, gian trá. ",
  "dn2:45.19": "Tránh xa chặt, giết, trói, cướp, tước đoạt, bạo lực. ",
  "dn2:45.20": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:45.21": "Tiểu giới đã xong. ",
  "dn2:46.0": "4.3.1.2. Trung giới ",
  "dn2:46.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống thọ hưởng việc phá hại hạt giống và thực vật, ",
  "dn2:46.2": "như là: hạt giống từ rễ, hạt giống từ thân, hạt giống từ đốt, hạt giống từ ngọn, hạt giống từ hạt là thứ nămthì vị ấy tránh xa việc phá hại hạt giống và thực vật như vậy. ",
  "dn2:46.3": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:47.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống thọ hưởng việc tích trữ và tiêu dùng, ",
  "dn2:47.2": "như là: tích trữ thức ăn, tích trữ đồ uống, tích trữ y phục, tích trữ xe cộ, tích trữ giường nằm, tích trữ hương thơm, tích trữ thực phẩm, ",
  "dn2:47.3": "thì vị ấy tránh xa việc tích trữ và tiêu dùng như vậy. ",
  "dn2:47.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:48.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống thọ hưởng các trò xem giải trí, ",
  "dn2:48.2": "như là: múa, hát, nhạc, kịch, kể chuyện, vỗ tay, la hét, trống đồng, biểu diễn trang trí, xiếc, đấu voi, đấu ngựa, đấu trâu, đấu bò, đấu dê, đấu cừu, đấu gà, đấu chim cút, đấu gậy, đấu quyền, đô vật, chiến đấu, duyệt binh, xem quân đội dàn trận, ",
  "dn2:48.3": "thì vị ấy tránh xa các trò xem giải trí như vậy. ",
  "dn2:48.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:49.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống thọ hưởng các trò chơi cờ bạc và giải trí buông thả, ",
  "dn2:49.2": "như là: cờ tám ô, cờ mười ô, cờ trên không, bước qua ô, lấy ô ngắn, chơi xúc xắc, bật que, tung chuỗi que, bài bạc bằng đồng tiền, chơi lá, xe đạp thu nhỏ, cung tên thu nhỏ, chữ đoán số, đoán tâm ý, chơi các trò bị chê trách, ",
  "dn2:49.3": "thì vị ấy tránh xa các trò chơi cờ bạc và giải trí buông thả như vậy. ",
  "dn2:49.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:50.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống thọ hưởng giường cao và giường lớn, ",
  "dn2:50.2": "như là: ghế dài, đi-văng, thảm len, chăn thêu, đệm màu trắng, đệm lông thú, mền đắp lông thú, đệm thêu, thảm bằng sợi chỉ vàng, gối da nai quý, thảm với đầu sư tử, thảm da thú, ghế có mái che, ghế có gối đỏ cả hai đầu, ",
  "dn2:50.3": "thì vị ấy tránh xa việc dùng giường cao và giường lớn như vậy. ",
  "dn2:50.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:51.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống thọ hưởng việc trang điểm và làm đẹp, ",
  "dn2:51.2": "như là: xoa bóp, xoa dầu, tắm gội, nhào bóp, dùng gương, xoa phấn thơm, dùng vòng hoa, nước hoa, thuốc bôi, bột mặt, kem bôi mặt, băng tay, búi tóc, gậy chống, ống đựng, kiếm, ô, dép thêu, khăn xếp, ngọc quý, phất trần, áo trắng dài tà, ",
  "dn2:51.3": "thì vị ấy tránh xa việc trang điểm và làm đẹp như vậy. ",
  "dn2:51.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:52.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống thọ hưởng việc nói chuyện phù phiếm, ",
  "dn2:52.2": "như là: nói chuyện về vua, nói chuyện về trộm cướp, nói chuyện về đại thần, nói chuyện về quân đội, nói chuyện về sợ hãi, nói chuyện về chiến tranh, nói chuyện về thức ăn, nói chuyện về uống rượu, nói chuyện về y phục, nói chuyện về giường nằm, nói chuyện về vòng hoa, nói chuyện về hương thơm, nói chuyện về thân tộc, nói chuyện về xe cộ, nói chuyện về làng xóm, nói chuyện về thị trấn, nói chuyện về thành phố, nói chuyện về đất nước, nói chuyện về phụ nữ, nói chuyện về anh hùng, nói chuyện về đường phố, nói chuyện về bến nước, nói chuyện về người đã mất, nói chuyện linh tinh, nói chuyện về nguồn gốc thế giới, nói chuyện về biển cả, nói chuyện về có hay không có, ",
  "dn2:52.3": "thì vị ấy tránh xa việc nói chuyện phù phiếm như vậy. ",
  "dn2:52.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:53.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống thọ hưởng việc tranh cãi, ",
  "dn2:53.2": "như là: 'Ông không hiểu Pháp và Luật này; ta mới hiểu Pháp và Luật này; ông làm sao hiểu được Pháp và Luật này; ông tu tập sai; ta mới tu tập đúng; lời ta nhất quán; lời ông không nhất quán; điều nên nói trước ông lại nói sau; điều nên nói sau ông lại nói trước; quan điểm của ông đã bị bác bỏ; luận điểm của ông đã bị đánh đổ; ông đã bị phản bác; hãy đi mà thoát khỏi lập luận đó, nếu ông có thể giải quyết được,' ",
  "dn2:53.3": "thì vị ấy tránh xa việc tranh cãi như vậy. ",
  "dn2:53.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:54.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống thọ hưởng việc làm sứ giả và đưa tin, ",
  "dn2:54.2": "như là: cho vua, cho đại thần của vua, cho người cùng giai cấp, cho bà-la-môn, cho gia chủ, cho trẻ em'hãy đi đây, hãy đến đó, hãy mang cái này, hãy lấy cái đó ở chỗ kia,' ",
  "dn2:54.3": "thì vị ấy tránh xa việc làm sứ giả và đưa tin như vậy. ",
  "dn2:54.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:55.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi là những kẻ lừa dối, nịnh hót, bói toán, lừa lọc, cầu lợi bằng lợi. Vị ấy tránh xa sự lừa dối và nịnh hót như vậy. ",
  "dn2:55.2": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:55.3": "Trung giới đã xong. ",
  "dn2:56.0": "4.3.1.3. Đại giới ",
  "dn2:56.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống bằng tà mạng qua các tà thuật, ",
  "dn2:56.2": "như là: xem tướng chi thể, xem điềm lành, xem điềm xấu, xem mộng, xem tướng tay, xem vết chuột gặm, xem lửa tế, xem muỗng tế, xem cám tế, xem vỏ trấu tế, xem gạo tế, xem bơ tế, xem dầu tế, xem miệng tế, xem máu tế; xem tướng chi thể, xem tướng đất, xem tướng vũ khí, xem tướng chiến binh, xem thuật trừ tà ma, xem thuật trừ bệnh ma, xem thuật trừ rắn, xem thuật giải độc, xem thuật trừ bọ cạp, xem thuật trừ chuột, xem thuật xem chim, xem thuật xem quạ, xem bói khả năng bay, xem thuật bảo vệ tên, xem điềm hươu, ",
  "dn2:56.3": "thì vị ấy tránh xa tà mạng qua các tà thuật như vậy. ",
  "dn2:56.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:57.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống bằng tà mạng qua các tà thuật, ",
  "dn2:57.2": "như là: xem tướng ngọc, xem tướng vải, xem tướng gậy, xem tướng kiếm, xem tướng đao, xem tướng tên, xem tướng cung, xem tướng vũ khí, xem tướng phụ nữ, xem tướng đàn ông, xem tướng trẻ em nam, xem tướng trẻ em nữ, xem tướng nô lệ nam, xem tướng nô lệ nữ, xem tướng voi, xem tướng ngựa, xem tướng trâu, xem tướng bò đực, xem tướng bò cái, xem tướng dê, xem tướng cừu, xem tướng gà, xem tướng chim cút, xem tướng kỳ nhông, xem tướng tai, xem tướng rùa, xem tướng hươu, ",
  "dn2:57.3": "thì vị ấy tránh xa tà mạng qua các tà thuật như vậy. ",
  "dn2:57.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:58.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống bằng tà mạng qua các tà thuật, ",
  "dn2:58.2": "như là: đoán vua sẽ xuất binh, đoán vua sẽ không xuất binh, đoán quân nội sẽ tiến, đoán quân ngoại sẽ rút, đoán quân ngoại sẽ tiến, đoán quân nội sẽ rút, đoán quân nội sẽ thắng, đoán quân ngoại sẽ thua, đoán quân ngoại sẽ thắng, đoán quân nội sẽ thua, đoán bên này sẽ thắng bên kia sẽ thua, ",
  "dn2:58.3": "thì vị ấy tránh xa tà mạng qua các tà thuật như vậy. ",
  "dn2:58.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:59.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống bằng tà mạng qua các tà thuật, ",
  "dn2:59.2": "như là: đoán sẽ có mưa thuận gió hòa, đoán sẽ có hạn hán, đoán sẽ no đủ, đoán sẽ đói kém, đoán sẽ an toàn, đoán sẽ nguy hiểm, đoán sẽ có bệnh tật, đoán sẽ mạnh khỏe; đếm trên ngón tay, tính toán số học, đo lường, làm thơ, nghiên cứu triết học tự nhiên; đoán nguyệt thực, đoán nhật thực, đoán sao thực, đoán mặt trăng mặt trời đi đúng đường, đoán mặt trăng mặt trời đi trái đường, đoán sao đi đúng đường, đoán sao đi trái đường, đoán sao băng, đoán lửa trên phương trời, đoán động đất, đoán sấm trời, đoán mặt trăng mặt trời và sao mọc, lặn, bị che khuất, hiện sáng; đoán quả báo của nguyệt thực, quả báo của nhật thực, quả báo của sao thực, quả báo của mặt trăng mặt trời đi đúng đường, quả báo của mặt trăng mặt trời đi trái đường, quả báo của sao đi đúng đường, quả báo của sao đi trái đường, quả báo của sao băng, quả báo của lửa trên phương trời, quả báo của động đất, quả báo của sấm trời, quả báo của mặt trăng mặt trời và sao mọc, lặn, bị che khuất, hiện sáng, ",
  "dn2:59.3": "thì vị ấy tránh xa tà mạng qua các tà thuật như vậy. ",
  "dn2:59.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:60.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống bằng tà mạng qua các tà thuật, ",
  "dn2:60.2": "như là: đoán sẽ mưa nhiều, đoán sẽ mưa ít, đoán sẽ no đủ, đoán sẽ đói kém, đoán sẽ an toàn, đoán sẽ nguy hiểm, đoán sẽ có bệnh, đoán sẽ mạnh khỏe; đếm trên ngón tay, tính toán, đo lường, làm thơ, triết học tự nhiên, ",
  "dn2:60.3": "thì vị ấy tránh xa tà mạng qua các tà thuật như vậy. ",
  "dn2:60.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:61.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống bằng tà mạng qua các tà thuật, ",
  "dn2:61.2": "như là: làm lễ rước dâu, làm lễ xuất giá, làm lễ hòa giải, làm lễ chia rẽ, làm lễ rải rắc, làm lễ giải rải rắc, làm bùa để được yêu, làm bùa để bị ghét, làm phép trừ thai, làm bùa buộc lưỡi, làm bùa bóp hàm, làm bùa bàn tay, làm bùa hàm, làm bùa tai, hỏi gương, hỏi thiếu nữ, hỏi thần, cúng dường mặt trời, cúng dường Đại Phạm Thiên, phun lửa, cầu phúc, ",
  "dn2:61.3": "thì vị ấy tránh xa tà mạng qua các tà thuật như vậy. ",
  "dn2:61.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:62.1": "Trong khi một số sa-môn, bà-la-môn dùng thức ăn do tín thí cúng dường rồi sống bằng tà mạng qua các tà thuật, ",
  "dn2:62.2": "như là: làm lễ an bình, làm lễ cầu nguyện, làm lễ trừ tà, làm lễ trừ bệnh lớn, làm lễ cầu mưa, làm lễ ngừng mưa, làm lễ trừ nạn, làm lễ chuẩn bị đất, rửa ráy, tắm gội, tế lửa, cho nôn mửa, xổ lên, xổ xuống, xổ đầu, nhỏ dầu tai, nhỏ mắt, điều trị bằng mũi, xoa thuốc mắt, bôi thuốc phản, điều trị mắt, phẫu thuật, điều trị trẻ em, kê thuốc gốc, dùng thuốc thảo mộc, ",
  "dn2:62.3": "thì vị ấy tránh xa tà mạng qua các tà thuật như vậy. ",
  "dn2:62.4": "Đây là phần giới hạnh của vị ấy. ",
  "dn2:63.1": "Tâu Đại Vương, Tỳ Kheo đầy đủ giới hạnh như vậy không thấy sợ hãi từ đâu, vì được thu thúc bởi giới. ",
  "dn2:63.2": "Tâu Đại Vương, cũng như vị vua được quán đảnh, đã phá tan kẻ thù, không thấy sợ hãi từ đâu vì được bảo vệ khỏi kẻ thù; ",
  "dn2:63.3": "cũng vậy, tâu Đại Vương, Tỳ Kheo đầy đủ giới hạnh như vậy không thấy sợ hãi từ đâu, vì được thu thúc bởi giới. ",
  "dn2:63.4": "Với nhóm giới thánh thiện này, vị ấy cảm nhận nội tâm an lạc không lỗi lầm. ",
  "dn2:63.5": "Như vậy, tâu Đại Vương, Tỳ Kheo đầy đủ giới hạnh. ",
  "dn2:63.6": "Đại giới đã xong. ",
  "dn2:64.0.1": "4.3.2. Định ",
  "dn2:64.0.2": "4.3.2.1. Phòng hộ các căn ",
  "dn2:64.1": "Thưa Đại Vương, thế nào là Tỳ Kheo phòng hộ các căn? ",
  "dn2:64.2": "Tâu Đại Vương, ở đây Tỳ Kheo khi mắt thấy sắc, không nắm giữ tướng tổng quát, không nắm giữ tướng chi tiết. ",
  "dn2:64.3": "Vì nếu không thu thúc nhãn căn, tham ái, ưu não, các bất thiện pháp sẽ xâm chiếm, vị ấy thực hành thu thúc, hộ trì nhãn căn, thực hành thu thúc nhãn căn. ",
  "dn2:64.4": "Khi tai nghe tiếng... ",
  "dn2:64.5": "Khi mũi ngửi mùi... ",
  "dn2:64.6": "Khi lưỡi nếm vị... ",
  "dn2:64.7": "Khi thân xúc chạm vật... ",
  "dn2:64.8": "Khi ý nhận biết pháp, không nắm giữ tướng tổng quát, không nắm giữ tướng chi tiết. ",
  "dn2:64.9": "Vì nếu không thu thúc ý căn, tham ái, ưu não, các bất thiện pháp sẽ xâm chiếm, vị ấy thực hành thu thúc, hộ trì ý căn, thực hành thu thúc ý căn. ",
  "dn2:64.10": "Với sự thu thúc các căn thánh thiện này, vị ấy cảm nhận nội tâm an lạc không ô nhiễm. ",
  "dn2:64.11": "Như vậy, tâu Đại Vương, Tỳ Kheo phòng hộ các căn. ",
  "dn2:65.0": "4.3.2.2. Chánh niệm và tỉnh giác ",
  "dn2:65.1": "Thưa Đại Vương, thế nào là Tỳ Kheo có chánh niệm và tỉnh giác? ",
  "dn2:65.2": "Tâu Đại Vương, ở đây Tỳ Kheo khi đi tới, đi lui đều tỉnh giác; khi nhìn tới, nhìn lui đều tỉnh giác; khi co tay, duỗi tay đều tỉnh giác; khi mang y, bình bát, y phục đều tỉnh giác; khi ăn, uống, nhai, nếm đều tỉnh giác; khi đại tiểu tiện đều tỉnh giác; khi đi, đứng, ngồi, nằm, thức, nói và im lặng đều tỉnh giác. ",
  "dn2:65.3": "Như vậy, tâu Đại Vương, Tỳ Kheo có chánh niệm và tỉnh giác. ",
  "dn2:66.0": "4.3.2.3. Biết đủ ",
  "dn2:66.1": "Thưa Đại Vương, thế nào là Tỳ Kheo biết đủ? ",
  "dn2:66.2": "Tâu Đại Vương, ở đây Tỳ Kheo biết đủ với y phục đủ để che thân, thức ăn khất thực đủ để no bụng. Dù đi đâu, vị ấy chỉ mang theo những thứ đó mà thôi. ",
  "dn2:66.3": "Tâu Đại Vương, cũng như con chim dù bay đến đâu cũng chỉ mang theo đôi cánh của nó; ",
  "dn2:66.4": "cũng vậy, tâu Đại Vương, Tỳ Kheo biết đủ với y phục đủ để che thân, thức ăn khất thực đủ để no bụng. Dù đi đâu, vị ấy chỉ mang theo những thứ đó mà thôi. ",
  "dn2:66.5": "Như vậy, tâu Đại Vương, Tỳ Kheo biết đủ. ",
  "dn2:67.0": "4.3.2.4. Đoạn trừ năm triền cái ",
  "dn2:67.1": "Với giới uẩn thánh thiện này, với sự thu thúc các căn thánh thiện, với chánh niệm và tỉnh giác thánh thiện, với sự biết đủ thánh thiện, ",
  "dn2:67.2": "vị ấy chọn chỗ ngồi vắng vẻrừng sâu, gốc cây, núi đồi, hang đá, hang núi, bãi tha ma, rừng hoang, ngoài trời, đống rơm. ",
  "dn2:67.3": "Sau khi ăn xong và đi khất thực trở về, vị ấy ngồi kiết già, lưng thẳng, an trú chánh niệm trước mặt. ",
  "dn2:68.1": "Vị ấy từ bỏ tham ái đối với đời, sống với tâm thoát khỏi tham ái, gột sạch tham ái ra khỏi tâm. ",
  "dn2:68.2": "Từ bỏ sân hận và oán thù, sống với tâm không sân hận, thương xót tất cả loài hữu tình, gột sạch sân hận và oán thù ra khỏi tâm. ",
  "dn2:68.3": "Từ bỏ hôn trầm và thụy miên, sống thoát khỏi hôn trầm và thụy miên, nhận thức ánh sáng, có chánh niệm và tỉnh giác, gột sạch hôn trầm và thụy miên ra khỏi tâm. ",
  "dn2:68.4": "Từ bỏ trạo cử và lo âu, sống không trạo cử, nội tâm yên tĩnh, gột sạch trạo cử và lo âu ra khỏi tâm. ",
  "dn2:68.5": "Từ bỏ hoài nghi, sống vượt qua hoài nghi, không do dự về các thiện pháp, gột sạch hoài nghi ra khỏi tâm. ",
  "dn2:69.1": "Tâu Đại Vương, như người vay tiền để kinh doanh, ",
  "dn2:69.2": "việc kinh doanh của người ấy thành công. ",
  "dn2:69.3": "Người ấy trả hết nợ cũ, còn dư lại đủ để nuôi vợ. ",
  "dn2:69.4": "Người ấy nghĩ: ",
  "dn2:69.5": "'Trước đây ta vay tiền để kinh doanh. '",
  "dn2:69.6": "Việc kinh doanh của ta thành công. ",
  "dn2:69.7": "Ta đã trả hết nợ cũ, còn dư lại đủ để nuôi vợ.' ",
  "dn2:69.8": "Do đó người ấy có được niềm vui, đạt được hạnh phúc. ",
  "dn2:70.1": "Tâu Đại Vương, như người bị bệnh, khổ sở, bệnh nặng; không muốn ăn, không có sức trong thân. ",
  "dn2:70.2": "Sau một thời gian, người ấy khỏi bệnh; lại muốn ăn, có sức trong thân. ",
  "dn2:70.3": "Người ấy nghĩ: ",
  "dn2:70.4": "'Trước đây ta bị bệnh, khổ sở, bệnh nặng; '",
  "dn2:70.5": "không muốn ăn, không có sức trong thân. ",
  "dn2:70.6": "Nay ta đã khỏi bệnh đó; ",
  "dn2:70.7": "lại muốn ăn, có sức trong thân.' ",
  "dn2:70.8": "Do đó người ấy có được niềm vui, đạt được hạnh phúc. ",
  "dn2:71.1": "Tâu Đại Vương, như người bị giam trong ngục. ",
  "dn2:71.2": "Sau một thời gian, người ấy được thả ra khỏi ngục an toàn, không bị hại, tài sản không bị tổn thất. ",
  "dn2:71.3": "Người ấy nghĩ: ",
  "dn2:71.4": "'Trước đây ta bị giam trong ngục, nay ta đã được thả ra khỏi ngục an toàn, không bị hại. '",
  "dn2:71.5": "Tài sản của ta không bị tổn thất.' ",
  "dn2:71.6": "Do đó người ấy có được niềm vui, đạt được hạnh phúc. ",
  "dn2:72.1": "Tâu Đại Vương, như người làm nô lệ, không tự chủ, lệ thuộc người khác, không thể đi đâu tùy ý. ",
  "dn2:72.2": "Sau một thời gian, người ấy thoát khỏi kiếp nô lệ, tự chủ, không lệ thuộc người khác, là người tự do, có thể đi đâu tùy ý. ",
  "dn2:72.3": "Người ấy nghĩ: ",
  "dn2:72.4": "'Trước đây ta làm nô lệ, không tự chủ, lệ thuộc người khác, không thể đi đâu tùy ý. '",
  "dn2:72.5": "Nay ta đã thoát khỏi kiếp nô lệ đó, tự chủ, không lệ thuộc người khác, là người tự do, có thể đi đâu tùy ý.' ",
  "dn2:72.6": "Do đó người ấy có được niềm vui, đạt được hạnh phúc. ",
  "dn2:73.1": "Tâu Đại Vương, như người có tiền của, có tài sản, đi vào vùng hoang vu đói kém, nguy hiểm. ",
  "dn2:73.2": "Sau một thời gian, người ấy vượt qua vùng hoang vu đó an toàn, đến được làng xóm an toàn, không có nguy hiểm. ",
  "dn2:73.3": "Người ấy nghĩ: ",
  "dn2:73.4": "'Trước đây ta có tiền của, có tài sản, đi vào vùng hoang vu đói kém, nguy hiểm. '",
  "dn2:73.5": "Nay ta đã vượt qua vùng hoang vu đó an toàn, đến được làng xóm an toàn, không có nguy hiểm.' ",
  "dn2:73.6": "Do đó người ấy có được niềm vui, đạt được hạnh phúc. ",
  "dn2:74.1": "Cũng vậy, tâu Đại Vương, Tỳ Kheo thấy năm triền cái chưa được đoạn trừ trong tự thânnhư nợ, như bệnh, như ngục, như nô lệ, như đường hoang vu. ",
  "dn2:74.2": "Tâu Đại Vương, Tỳ Kheo thấy năm triền cái đã được đoạn trừ trong tự thânnhư hết nợ, như khỏi bệnh, như thoát ngục, như được tự do, như đến vùng an toàn. ",
  "dn2:74.3": "Cũng vậy, tâu Đại Vương, Tỳ Kheo thấy năm triền cái đã được đoạn trừ trong tự thân. ",
  "dn2:74.4": "Khi vị ấy thấy năm triền cái đã được đoạn trừ trong tự thân, hỷ lạc sanh khởi; khi hỷ lạc, phỉ sanh khởi; khi có phỉ, thân được an tịnh; khi thân an tịnh, lạc thọ sanh khởi; khi có lạc, tâm được định tĩnh. ",
  "dn2:75.0": "4.3.2.5. Sơ thiền ",
  "dn2:75.1": "Vị ấy ly khai dục lạc, ly khai các bất thiện pháp, chứng và trú Sơ thiền, có tầm và tứ, có hỷ lạc do ly dục sanh. ",
  "dn2:75.2": "Vị ấy thấm nhuần, tưới khắp, làm cho đầy tràn và lan tỏa thân này với hỷ lạc do ly dục sanh, không có bất kỳ phần nào của toàn thân không được hỷ lạc do ly dục thấm nhuần. ",
  "dn2:76.1": "Tâu Đại Vương, như người thợ tắm hay học trò người thợ tắm khéo léo, rải bột tắm vào chậu đồng rồi nhào bột với nước, nhào đi nhào lại; khối bột tắm thấm nhuần nước, thấm đầy nước, ướt cả trong lẫn ngoài, nhưng không nhỏ giọt; ",
  "dn2:76.2": "cũng vậy, tâu Đại Vương, Tỳ Kheo thấm nhuần, tưới khắp, làm cho đầy tràn và lan tỏa thân này với hỷ lạc do ly dục sanh, không có bất kỳ phần nào của toàn thân không được hỷ lạc do ly dục thấm nhuần. ",
  "dn2:76.3": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn hai quả báo trước. ",
  "dn2:77.0": "4.3.2.6. Nhị thiền ",
  "dn2:77.1": "Thêm nữa, tâu Đại Vương, Tỳ Kheo do tầm và tứ đã lắng xuống, nội tâm trở nên thanh tịnh và nhất điểm, không tầm không tứ, chứng và trú Nhị thiền, có hỷ lạc do định sanh. ",
  "dn2:77.2": "Vị ấy thấm nhuần, tưới khắp, làm cho đầy tràn và lan tỏa thân này với hỷ lạc do định sanh, không có bất kỳ phần nào của toàn thân không được hỷ lạc do định thấm nhuần. ",
  "dn2:78.1": "Tâu Đại Vương, như hồ nước sâu có nước phun lên từ bên trong, không có nguồn nước từ phía đông, không có nguồn nước từ phía nam, không có nguồn nước từ phía tây, không có nguồn nước từ phía bắc, và trời cũng không thỉnh thoảng đổ mưa xuống; ",
  "dn2:78.2": "nhưng từ lòng hồ đó, dòng nước mát mẻ phun lên thấm nhuần, tưới khắp, làm cho đầy tràn và lan tỏa khắp hồ nước đó với nước mát, không có bất kỳ phần nào của hồ nước không được nước mát thấm đến; ",
  "dn2:78.3": "cũng vậy, tâu Đại Vương, Tỳ Kheo thấm nhuần, tưới khắp, làm cho đầy tràn và lan tỏa thân này với hỷ lạc do định sanh, không có bất kỳ phần nào của toàn thân không được hỷ lạc do định thấm nhuần. ",
  "dn2:78.4": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:79.0": "4.3.2.7. Tam thiền ",
  "dn2:79.1": "Thêm nữa, tâu Đại Vương, Tỳ Kheo do ly hỷ, trú xả, có chánh niệm và tỉnh giác, thân cảm lạc thọ mà các bậc Thánh gọi là 'người có xả và niệm, an trú lạc thọ,' chứng và trú Tam thiền. ",
  "dn2:79.2": "Vị ấy thấm nhuần, tưới khắp, làm cho đầy tràn và lan tỏa thân này với lạc thọ không có hỷ, không có bất kỳ phần nào của toàn thân không được lạc thọ không có hỷ thấm nhuần. ",
  "dn2:80.1": "Tâu Đại Vương, như trong ao sen xanh, ao sen đỏ, ao sen trắng, có những bông sen xanh, sen đỏ, sen trắng sanh trong nước, lớn lên trong nước, không vươn lên khỏi nước, sống chìm trong nước, từ ngọn đến rễ đều thấm nhuần nước mát, đầy nước mát, thấm đầy nước mát, không có bất kỳ phần nào của hoa sen không được nước mát thấm đến; ",
  "dn2:80.2": "cũng vậy, tâu Đại Vương, Tỳ Kheo thấm nhuần, tưới khắp, làm cho đầy tràn và lan tỏa thân này với lạc thọ không có hỷ, không có bất kỳ phần nào của toàn thân không được lạc thọ không có hỷ thấm nhuần. ",
  "dn2:80.3": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:81.0": "4.3.2.8. Tứ thiền ",
  "dn2:81.1": "Thêm nữa, tâu Đại Vương, Tỳ Kheo đoạn trừ lạc thọ và khổ thọ, diệt trừ hỷ ưu đã có trước, chứng và trú Tứ thiềnkhông khổ không lạc, xả và niệm thanh tịnh. ",
  "dn2:81.2": "Vị ấy ngồi với tâm hoàn toàn thanh tịnh và trong sáng lan tỏa khắp thân, không có bất kỳ phần nào của toàn thân không được tâm hoàn toàn thanh tịnh và trong sáng thấm nhuần. ",
  "dn2:82.1": "Tâu Đại Vương, như người ngồi đắp khắp thân từ đầu đến chân bằng tấm vải trắng, không có bất kỳ phần nào của toàn thân không được tấm vải trắng che phủ; ",
  "dn2:82.2": "cũng vậy, tâu Đại Vương, Tỳ Kheo ngồi với tâm hoàn toàn thanh tịnh và trong sáng lan tỏa khắp thân, không có bất kỳ phần nào của toàn thân không được tâm hoàn toàn thanh tịnh và trong sáng thấm nhuần. ",
  "dn2:82.3": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:83.0.1": "4.3.3. Tám loại trí tuệ ",
  "dn2:83.0.2": "4.3.3.1. Trí tuệ minh sát ",
  "dn2:83.1": "Với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, vị ấy hướng tâm và dẫn tâm đến trí tuệ và tri kiến. ",
  "dn2:83.2": "Vị ấy biết rõ như vầy: ",
  "dn2:83.3": "'Thân này của ta có hình sắc, do bốn đại tạo thành, do cha mẹ sanh ra, được nuôi bằng cơm cháo, vô thường, phải bị mài mòn, tiêu hoại, tan rã, biến diệt; '",
  "dn2:83.4": "và thức này của ta bị ràng buộc vào đó, bị trói buộc vào đó.' ",
  "dn2:84.1": "Tâu Đại Vương, như viên ngọc lưu ly quý giá, tám mặt, được mài giũa khéo léo, trong suốt, sáng rỡ, không tỳ vết, đầy đủ mọi đặc tính. ",
  "dn2:84.2": "Trong đó có sợi chỉ xuyên qua, màu xanh hay vàng hay đỏ hay trắng hay vàng nhạt. ",
  "dn2:84.3": "Người có mắt cầm trên tay để nhìn thấy rõ ràng: ",
  "dn2:84.4": "'Đây là viên ngọc lưu ly quý giá, tám mặt, được mài giũa khéo léo, trong suốt, sáng rỡ, không tỳ vết, đầy đủ mọi đặc tính; '",
  "dn2:84.5": "trong đó có sợi chỉ xuyên qua, màu xanh hay vàng hay đỏ hay trắng hay vàng nhạt.' ",
  "dn2:84.6": "Cũng vậy, tâu Đại Vương, Tỳ Kheo với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, hướng tâm và dẫn tâm đến trí tuệ và tri kiến. ",
  "dn2:84.7": "Vị ấy biết rõ như vầy: ",
  "dn2:84.8": "'Thân này của ta có hình sắc, do bốn đại tạo thành, do cha mẹ sanh ra, được nuôi bằng cơm cháo, vô thường, phải bị mài mòn, tiêu hoại, tan rã, biến diệt; '",
  "dn2:84.9": "và thức này của ta bị ràng buộc vào đó, bị trói buộc vào đó.' ",
  "dn2:84.10": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:85.0": "4.3.3.2. Trí tạo thân ý sanh ",
  "dn2:85.1": "Với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, vị ấy hướng tâm và dẫn tâm đến việc tạo ra thân ý sanh. ",
  "dn2:85.2": "Từ thân này, vị ấy tạo ra thân khác có hình sắc, do ý tạo, đầy đủ mọi chi tiết, không thiếu căn. ",
  "dn2:86.1": "Tâu Đại Vương, như người rút một cây lau ra khỏi bọc cỏ muñja. ",
  "dn2:86.2": "Người ấy nghĩ: ",
  "dn2:86.3": "'Đây là bọc cỏ muñja, đây là cây lau; cỏ muñja một đàng, cây lau một nẻo; cây lau đã được rút ra khỏi bọc cỏ muñja.' ",
  "dn2:86.4": "Hay như người rút kiếm ra khỏi bao kiếm. ",
  "dn2:86.5": "Người ấy nghĩ: ",
  "dn2:86.6": "'Đây là kiếm, đây là bao kiếm; kiếm một đàng, bao một nẻo; kiếm đã được rút ra khỏi bao.' ",
  "dn2:86.7": "Hay như người lấy rắn ra khỏi giỏ. ",
  "dn2:86.8": "Người ấy nghĩ: ",
  "dn2:86.9": "'Đây là con rắn, đây là cái giỏ. Con rắn một đàng, cái giỏ một nẻo; con rắn đã được lấy ra khỏi giỏ.' ",
  "dn2:86.10": "Cũng vậy, tâu Đại Vương, Tỳ Kheo với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, hướng tâm và dẫn tâm đến việc tạo ra thân ý sanh. ",
  "dn2:86.11": "Từ thân này, vị ấy tạo ra thân khác có hình sắc, do ý tạo, đầy đủ mọi chi tiết, không thiếu căn. ",
  "dn2:86.12": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:87.0": "4.3.3.3. Trí thần thông ",
  "dn2:87.1": "Với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, vị ấy hướng tâm và dẫn tâm đến các loại thần thông. ",
  "dn2:87.2": "Vị ấy chứng đạt các loại thần thôngmột thân hóa ra nhiều thân, nhiều thân hợp thành một thân; hiện ra, biến mất; đi xuyên qua tường, qua thành, qua núi như đi trong không khí; lặn xuống và trồi lên trong đất như trong nước; đi trên nước không chìm như đi trên đất; bay ngồi kiết già trên không như con chim; dùng tay sờ mó mặt trăng, mặt trời dù rất oai thần và hùng mạnh; với thân xác, ngài thực hành quyền năng đến tận cõi Phạm Thiên. ",
  "dn2:88.1": "Tâu Đại Vương, như người thợ gốm giỏi hay học trò của thợ gốm, từ đất sét đã chuẩn bị tốt, có thể làm ra bất kỳ đồ vật nào tùy ý. ",
  "dn2:88.2": "Hay như người thợ ngà giỏi hay học trò của thợ ngà, từ ngà voi đã chuẩn bị tốt, có thể làm ra bất kỳ đồ vật nào tùy ý. ",
  "dn2:88.3": "Hay như người thợ vàng giỏi hay học trò của thợ vàng, từ vàng đã chuẩn bị tốt, có thể làm ra bất kỳ đồ vật nào tùy ý. ",
  "dn2:88.4": "Cũng vậy, tâu Đại Vương, Tỳ Kheo với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, hướng tâm và dẫn tâm đến các loại thần thông. ",
  "dn2:88.5": "Vị ấy chứng đạt các loại thần thôngmột thân hóa ra nhiều thân, nhiều thân hợp thành một thân; hiện ra, biến mất; đi xuyên qua tường, qua thành, qua núi như đi trong không khí; lặn xuống và trồi lên trong đất như trong nước; đi trên nước không chìm như đi trên đất; bay ngồi kiết già trên không như con chim; dùng tay sờ mó mặt trăng, mặt trời dù rất oai thần và hùng mạnh; với thân xác, ngài thực hành quyền năng đến tận cõi Phạm Thiên. ",
  "dn2:88.6": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:89.0": "4.3.3.4. Trí thiên nhĩ ",
  "dn2:89.1": "Với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, vị ấy hướng tâm và dẫn tâm đến thiên nhĩ giới. ",
  "dn2:89.2": "Với thiên nhĩ thanh tịnh vượt qua nhĩ căn của người, vị ấy nghe cả hai loại tiếngtiếng cõi trời và tiếng người, ở xa hay ở gần. ",
  "dn2:90.1": "Tâu Đại Vương, như người đi đường dài, nghe tiếng trống, tiếng trống con, tiếng tù và, tiếng trống nhỏ, tiếng cồng chiêng. Người ấy nghĩ: 'Đây là tiếng trống, đây là tiếng trống con, đây là tiếng tù và, tiếng trống nhỏ, tiếng cồng chiêng.' ",
  "dn2:90.2": "Cũng vậy, tâu Đại Vương, Tỳ Kheo với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, hướng tâm và dẫn tâm đến thiên nhĩ giới. ",
  "dn2:90.3": "Với thiên nhĩ thanh tịnh vượt qua nhĩ căn của người, vị ấy nghe cả hai loại tiếngtiếng cõi trời và tiếng người, ở xa hay ở gần. ",
  "dn2:90.4": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:91.0": "4.3.3.5. Trí tha tâm ",
  "dn2:91.1": "Với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, vị ấy hướng tâm và dẫn tâm đến trí biết tâm người khác. ",
  "dn2:91.2": "Vị ấy dùng tâm của mình biết được tâm của các chúng sanh, con người khác",
  "dn2:91.3": "tâm có tham, biết là 'tâm có tham'; ",
  "dn2:91.4": "tâm không tham, biết là 'tâm không tham'; ",
  "dn2:91.5": "tâm có sân, biết là 'tâm có sân'; ",
  "dn2:91.6": "tâm không sân, biết là 'tâm không sân'; ",
  "dn2:91.7": "tâm có si, biết là 'tâm có si'; ",
  "dn2:91.8": "tâm không si, biết là 'tâm không si'; ",
  "dn2:91.9": "tâm thu nhiếp, biết là 'tâm thu nhiếp'; ",
  "dn2:91.10": "tâm tán loạn, biết là 'tâm tán loạn'; ",
  "dn2:91.11": "tâm đại, biết là 'tâm đại'; ",
  "dn2:91.12": "tâm không đại, biết là 'tâm không đại'; ",
  "dn2:91.13": "tâm có thể vượt qua, biết là 'tâm có thể vượt qua'; ",
  "dn2:91.14": "tâm vô thượng, biết là 'tâm vô thượng'; ",
  "dn2:91.15": "tâm định tĩnh, biết là 'tâm định tĩnh'; ",
  "dn2:91.16": "tâm không định tĩnh, biết là 'tâm không định tĩnh'; ",
  "dn2:91.17": "tâm giải thoát, biết là 'tâm giải thoát'; ",
  "dn2:91.18": "tâm chưa giải thoát, biết là 'tâm chưa giải thoát'. ",
  "dn2:92.1": "Tâu Đại Vương, như người phụ nữ hay nam giới trẻ tuổi, ưa trang điểm, soi mặt trong gương sạch và trong, hay trong bát nước sạch, nếu có vết đen thì biết là có vết đen, không có vết đen thì biết là không có vết đen; ",
  "dn2:92.2": "cũng vậy, tâu Đại Vương, Tỳ Kheo với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, hướng tâm và dẫn tâm đến trí biết tâm người khác. ",
  "dn2:92.3": "Vị ấy dùng tâm của mình biết được tâm của các chúng sanh, con người khác",
  "dn2:92.4": "tâm có tham, biết là 'tâm có tham'; ",
  "dn2:92.5": "tâm không tham, biết là 'tâm không tham'; ",
  "dn2:92.6": "tâm có sân, biết là 'tâm có sân'; ",
  "dn2:92.7": "tâm không sân, biết là 'tâm không sân'; ",
  "dn2:92.8": "tâm có si, biết là 'tâm có si'; ",
  "dn2:92.9": "tâm không si, biết là 'tâm không si'; ",
  "dn2:92.10": "tâm thu nhiếp, biết là 'tâm thu nhiếp'; ",
  "dn2:92.11": "tâm tán loạn, biết là 'tâm tán loạn'; ",
  "dn2:92.12": "tâm đại, biết là 'tâm đại'; ",
  "dn2:92.13": "tâm không đại, biết là 'tâm không đại'; ",
  "dn2:92.14": "tâm có thể vượt qua, biết là 'tâm có thể vượt qua'; ",
  "dn2:92.15": "tâm vô thượng, biết là 'tâm vô thượng'; ",
  "dn2:92.16": "tâm định tĩnh, biết là 'tâm định tĩnh'; ",
  "dn2:92.17": "tâm không định tĩnh, biết là 'tâm không định tĩnh'; ",
  "dn2:92.18": "tâm giải thoát, biết là 'tâm giải thoát'; ",
  "dn2:92.19": "tâm chưa giải thoát, biết là 'tâm chưa giải thoát'. ",
  "dn2:92.20": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:93.0": "4.3.3.6. Trí túc mệnh thông ",
  "dn2:93.1": "Với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, vị ấy hướng tâm và dẫn tâm đến trí nhớ các đời quá khứ. ",
  "dn2:93.2": "Vị ấy nhớ lại nhiều đời quá khứmột đời, hai đời, ba đời, bốn đời, năm đời, mười đời, hai mươi đời, ba mươi đời, bốn mươi đời, năm mươi đời, một trăm đời, một nghìn đời, một trăm nghìn đời, nhiều kiếp thế giới thu lại, nhiều kiếp thế giới mở ra, nhiều kiếp thế giới thu lại và mở ra; 'ở đó ta có tên thế này, dòng họ thế này, màu da thế này, thức ăn thế này, cảm nhận khổ vui thế này, tuổi thọ thế này; sau khi chết ở đó, ta tái sanh ở chỗ kia; ở đó ta có tên thế này, dòng họ thế này, màu da thế này, thức ăn thế này, cảm nhận khổ vui thế này, tuổi thọ thế này; sau khi chết ở đó, ta tái sanh ở đây.' Như vậy vị ấy nhớ lại nhiều đời quá khứ với đặc điểm và chi tiết cụ thể. ",
  "dn2:94.1": "Tâu Đại Vương, như người từ làng mình đi đến làng khác, rồi từ làng đó đi đến làng khác nữa. Người ấy trở về lại làng của mình. Người ấy nghĩ: 'Ta đã từ làng mình đến làng kia, ở đó ta đứng thế này, ngồi thế này, nói thế này, im lặng thế này; rồi ta từ làng đó đến làng nữa kia, ở đó ta cũng đứng thế này, ngồi thế này, nói thế này, im lặng thế này; rồi ta từ làng đó trở về làng của mình.' ",
  "dn2:94.2": "Cũng vậy, tâu Đại Vương, Tỳ Kheo với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, hướng tâm và dẫn tâm đến trí nhớ các đời quá khứ. ",
  "dn2:94.3": "Vị ấy nhớ lại nhiều đời quá khứmột đời, hai đời, ba đời, bốn đời, năm đời, mười đời, hai mươi đời, ba mươi đời, bốn mươi đời, năm mươi đời, một trăm đời, một nghìn đời, một trăm nghìn đời, nhiều kiếp thế giới thu lại, nhiều kiếp thế giới mở ra, nhiều kiếp thế giới thu lại và mở ra; 'ở đó ta có tên thế này, dòng họ thế này, màu da thế này, thức ăn thế này, cảm nhận khổ vui thế này, tuổi thọ thế này; sau khi chết ở đó, ta tái sanh ở chỗ kia; ở đó ta có tên thế này, dòng họ thế này, màu da thế này, thức ăn thế này, cảm nhận khổ vui thế này, tuổi thọ thế này; sau khi chết ở đó, ta tái sanh ở đây.' Như vậy vị ấy nhớ lại nhiều đời quá khứ với đặc điểm và chi tiết cụ thể. ",
  "dn2:94.4": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:95.0": "4.3.3.7. Trí thiên nhãn ",
  "dn2:95.1": "Với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, vị ấy hướng tâm và dẫn tâm đến trí về sự tử sanh của chúng sinh. ",
  "dn2:95.2": "Với thiên nhãn thanh tịnh, vượt qua nhãn căn của người, vị ấy thấy chúng sinh đang chết và tái sanh, hạ liệt hay cao sang, đẹp đẽ hay xấu xí, may mắn hay bất hạnh, biết chúng sinh tái sanh theo nghiệp của họ: 'Những chúng sinh này có hành vi xấu về thân, lời và ý, phỉ báng các bậc Thánh, có tà kiến, tạo nghiệp theo tà kiến; sau khi thân tan rã, mạng chung, họ tái sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Còn những chúng sinh này có hành vi tốt về thân, lời và ý, không phỉ báng các bậc Thánh, có chánh kiến, tạo nghiệp theo chánh kiến; sau khi thân tan rã, mạng chung, họ tái sanh vào cõi lành, cõi trời.' Như vậy, với thiên nhãn thanh tịnh vượt qua nhãn căn của người, vị ấy thấy chúng sinh đang chết và tái sanh, hạ liệt hay cao sang, đẹp đẽ hay xấu xí, may mắn hay bất hạnh, biết chúng sinh tái sanh theo nghiệp của họ. ",
  "dn2:96.1": "Tâu Đại Vương, như người có mắt đứng tại ngã tư đường, thấy người đi vào nhà, người đi ra nhà, người đi trên đường cái, người ngồi ở giữa ngã tư. Người ấy nghĩ: 'Những người này đi vào nhà, những người này đi ra, những người này đi trên đường cái, những người này ngồi ở giữa ngã tư.' ",
  "dn2:96.2": "Cũng vậy, tâu Đại Vương, Tỳ Kheo với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, hướng tâm và dẫn tâm đến trí về sự tử sanh của chúng sinh. ",
  "dn2:96.3": "Với thiên nhãn thanh tịnh, vượt qua nhãn căn của người, vị ấy thấy chúng sinh đang chết và tái sanh, hạ liệt hay cao sang, đẹp đẽ hay xấu xí, may mắn hay bất hạnh, biết chúng sinh tái sanh theo nghiệp của họ: 'Những chúng sinh này có hành vi xấu về thân, lời và ý, phỉ báng các bậc Thánh, có tà kiến, tạo nghiệp theo tà kiến; sau khi thân tan rã, mạng chung, họ tái sanh vào cõi dữ, ác thú, đọa xứ, địa ngục. Còn những chúng sinh này có hành vi tốt về thân, lời và ý, không phỉ báng các bậc Thánh, có chánh kiến, tạo nghiệp theo chánh kiến; sau khi thân tan rã, mạng chung, họ tái sanh vào cõi lành, cõi trời.' Như vậy, với thiên nhãn thanh tịnh vượt qua nhãn căn của người, vị ấy thấy chúng sinh đang chết và tái sanh, hạ liệt hay cao sang, đẹp đẽ hay xấu xí, may mắn hay bất hạnh; biết chúng sinh tái sanh theo nghiệp của họ. ",
  "dn2:96.4": "Đây cũng là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:97.0": "4.3.3.8. Trí lậu tận ",
  "dn2:97.1": "Với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, vị ấy hướng tâm và dẫn tâm đến trí đoạn diệt các lậu hoặc. ",
  "dn2:97.2": "Vị ấy biết như thật: 'Đây là khổ'; biết như thật: 'Đây là nguyên nhân của khổ'; biết như thật: 'Đây là sự diệt khổ'; biết như thật: 'Đây là con đường dẫn đến diệt khổ'. ",
  "dn2:97.3": "Biết như thật: 'Đây là các lậu hoặc'; biết như thật: 'Đây là nguyên nhân của lậu hoặc'; biết như thật: 'Đây là sự diệt lậu hoặc'; biết như thật: 'Đây là con đường dẫn đến diệt lậu hoặc'. ",
  "dn2:97.4": "Khi biết và thấy như vậy, tâm vị ấy giải thoát khỏi dục lậu, giải thoát khỏi hữu lậu, giải thoát khỏi vô minh lậu. ",
  "dn2:97.5": "Khi giải thoát, có trí biết 'đã giải thoát'. ",
  "dn2:97.6": "Vị ấy biết: 'Sanh đã tận, phạm hạnh đã thành, việc cần làm đã làm, không còn trở lại đời này nữa.' ",
  "dn2:98.1": "Tâu Đại Vương, như hồ nước ở vùng núi non, trong sáng, không vẩn đục. Người có mắt đứng trên bờ thấy con trai, con ốc, sỏi đá, đàn cá đang bơi và đứng yên. Người ấy nghĩ: 'Hồ nước này trong sáng, không vẩn đục. Ở đây có con trai, con ốc, sỏi đá, đàn cá đang bơi và đứng yên.' ",
  "dn2:98.2": "Cũng vậy, tâu Đại Vương, Tỳ Kheo với tâm định tĩnh, thuần tịnh, trong sáng, không cấu uế, không phiền não, nhu nhuyến, dễ sử dụng, vững chắc, bình tĩnh như vậy, hướng tâm và dẫn tâm đến trí đoạn diệt các lậu hoặc. ",
  "dn2:98.3": "Vị ấy biết như thật: 'Đây là khổ'; biết như thật: 'Đây là nguyên nhân của khổ'; biết như thật: 'Đây là sự diệt khổ'; biết như thật: 'Đây là con đường dẫn đến diệt khổ'. ",
  "dn2:98.4": "Biết như thật: 'Đây là các lậu hoặc'; biết như thật: 'Đây là nguyên nhân của lậu hoặc'; biết như thật: 'Đây là sự diệt lậu hoặc'; biết như thật: 'Đây là con đường dẫn đến diệt lậu hoặc'. ",
  "dn2:98.5": "Khi biết và thấy như vậy, tâm vị ấy giải thoát khỏi dục lậu, giải thoát khỏi hữu lậu, giải thoát khỏi vô minh lậu. ",
  "dn2:98.6": "Khi giải thoát, có trí biết 'đã giải thoát'. ",
  "dn2:98.7": "Vị ấy biết: 'Sanh đã tận, phạm hạnh đã thành, việc cần làm đã làm, không còn trở lại đời này nữa.' ",
  "dn2:98.8": "Tâu Đại Vương, đây là quả báo hiện tại của đời sống sa-môn cao thượng hơn và vi diệu hơn các quả báo trước. ",
  "dn2:98.9": "Tâu Đại Vương, không có quả báo hiện tại nào của đời sống sa-môn cao hơn hay vi diệu hơn quả báo hiện tại này.' ",
  "dn2:99.0": "5. Vua Ajātasattu xin quy y ",
  "dn2:99.1": "Khi được nghe vậy, vua Magadha Ajātasattu Vedehiputta thưa với Đức Thế Tôn: ",
  "dn2:99.2": "'Bạch Thế Tôn, tuyệt vời thay! Bạch Thế Tôn, tuyệt vời thay! '",
  "dn2:99.3": "Bạch Thế Tôn, giống như người dựng lại những gì bị ngã xuống, mở ra những gì bị che khuất, chỉ đường cho người lạc lối, hay thắp đèn trong bóng tối để người có mắt thấy được hình sắc; cũng vậy, Đức Thế Tôn đã dùng nhiều cách để giảng Pháp. ",
  "dn2:99.4": "Con xin quy y Thế Tôn, quy y Pháp và quy y chúng Tỳ Kheo. ",
  "dn2:99.5": "Xin Thế Tôn nhận con làm người cư sĩ từ nay cho đến khi mạng chung quy y như vậy. ",
  "dn2:99.6": "Bạch Thế Tôn, con đã phạm lỗi lầmdo ngu muội, do si mê, do bất thiện mà con đã tước đoạt mạng sống của phụ vương là vị vua chân chánh, bậc pháp vương, vì lòng tham quyền lực. ",
  "dn2:99.7": "Bạch Thế Tôn, xin Thế Tôn chấp nhận lỗi lầm đó của con là lỗi lầm, để con phòng hộ trong tương lai.' ",
  "dn2:100.1": "'Đúng vậy, tâu Đại Vương, Ngài đã phạm lỗi lầmdo ngu muội, do si mê, do bất thiện mà Ngài đã tước đoạt mạng sống của phụ vương là vị vua chân chánh, bậc pháp vương. '",
  "dn2:100.2": "Nhưng vì Ngài nhận ra lỗi lầm là lỗi lầm và đúng theo pháp mà sám hối, ta chấp nhận điều đó. ",
  "dn2:100.3": "Đây là sự tăng trưởng trong Thánh Luật, tâu Đại Vươngngười nhận ra lỗi lầm là lỗi lầm và đúng theo pháp mà sám hối, phòng hộ trong tương lai.' ",
  "dn2:101.1": "Khi được nghe vậy, vua Magadha Ajātasattu Vedehiputta thưa với Đức Thế Tôn: ",
  "dn2:101.2": "'Bạch Thế Tôn, nay chúng con xin phép cáo lui, chúng con còn nhiều việc phải làm.' ",
  "dn2:101.3": "'Tâu Đại Vương, Ngài hãy tùy thời định liệu.' ",
  "dn2:101.4": "Khi ấy, vua Magadha Ajātasattu Vedehiputta hoan hỷ, tán thán lời Đức Thế Tôn, đứng dậy khỏi chỗ ngồi, đảnh lễ Đức Thế Tôn, đi nhiễu bên phải rồi ra đi. ",
  "dn2:102.1": "Khi ấy, ngay sau khi vua Magadha Ajātasattu Vedehiputta ra đi, Đức Thế Tôn gọi các Tỳ Kheo: ",
  "dn2:102.2": "'Này các Tỳ Kheo, vị vua đó đã bị tổn hại. '",
  "dn2:102.3": "Này các Tỳ Kheo, vị vua đó đã bị hủy hoại. ",
  "dn2:102.4": "Này các Tỳ Kheo, nếu vua đó đã không tước đoạt mạng sống của phụ vương là vị vua chân chánh, bậc pháp vương, thì ngay tại chỗ ngồi này, Pháp nhãn trong sạch, không cấu uế đã sanh khởi trong vua.' ",
  "dn2:102.5": "Đó là lời Đức Thế Tôn đã dạy. ",
  "dn2:102.6": "Các Tỳ Kheo hoan hỷ, tín thọ lời Đức Thế Tôn. ",
  "dn2:102.7": "Kinh Sa-môn Quả, bài thứ hai, đã xong. "
}
